  const [newRoleColor, setNewRoleColor] = useState('blue');

  const isSuperAdmin = currentUser?.name === 'Birk Haugnes';

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let passToSave: string | undefined = undefined;
    if (showPasswordSection && newPassword) {
        if (newPassword !== confirmPassword) { setPasswordError('Passordene er ikke like'); return; }
        if (newPassword.length < 4) { setPasswordError('Passordet må være minst 4 tegn'); return; }
        passToSave = newPassword;
    }
    onSave({ ...settings, phoneNumber, email, pushEnabled: settings.pushEnabled }, passToSave);
  };

  const renderProfile = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-4">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Brukerprofil</h4>
                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="block text-sm font-medium text-slate-700">Telefonnummer</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none"><Smartphone className="h-4 w-4 text-gray-400" /></div>
                            <input type="tel" value={phoneNumber} onChange={(e) => setPhoneNumber(e.target.value)} placeholder="912 34 567" className="block w-full pl-9 py-2.5 text-sm border border-slate-300 rounded-xl bg-white" />
                        </div>
                    </div>
                </div>
            </div>

            <div className="space-y-4">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Passord</h4>
                {!showPasswordSection ? (
                    <button type="button" onClick={() => setShowPasswordSection(true)} className="w-full flex items-center justify-between p-3 bg-white border border-slate-200 rounded-xl hover:bg-slate-50 transition-colors">
                        <div className="flex items-center"><Lock size={18} className="text-slate-400 mr-3" /><span className="text-sm font-medium text-slate-700">Endre Passord</span></div>
                        <KeyRound size={16} className="text-slate-300" />
                    </button>
                ) : (
                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 space-y-3">
                        <input type="password" value={newPassword} onChange={(e) => {setNewPassword(e.target.value); setPasswordError('');}} className="w-full p-2.5 text-sm border border-slate-300 rounded-lg" placeholder="Nytt passord" />
                        <input type="password" value={confirmPassword} onChange={(e) => {setConfirmPassword(e.target.value); setPasswordError('');}} className="w-full p-2.5 text-sm border border-slate-300 rounded-lg" placeholder="Gjenta passord" />
