import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { storage } from './services/storageService';
import { cloudSave, cloudDelete, cloudFetchAll, subscribeToCloudChanges, cloudSaveBulk } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud, CloudOff, RefreshCw, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);
  const [showErrorToast, setShowErrorToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [presetFines, setPresetFines] = useState<PresetFine[]>([]);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>([]);
  const [passwords, setPasswords] = useState<Record<string, string>>({});

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  // Initial load
  useEffect(() => {
    const loadedFines = storage.get<FineEntry[]>('fines', []);
    const loadedPresets = storage.get<PresetFine[]>('presets', DEFAULT_PRESET_FINES);
    const loadedRoles = storage.get<RoleDefinition[]>('roles', DEFAULT_ROLES);
    const loadedSettings = storage.get<Record<string, UserSettings>>('settings', {});
    const loadedPasswords = storage.get<Record<string, string>>('passwords', {});

    // Basis-oppsett av spillere
    const storedPlayers = storage.get<Player[]>('players', []);
    const initialPlayerMap = new Map<string, Player>();
    DEFAULT_PLAYERS.forEach(p => initialPlayerMap.set(p.id, p));
    storedPlayers.forEach(p => initialPlayerMap.set(p.id, p));
    const initialPlayers = Array.from(initialPlayerMap.values());

    setFines(loadedFines);
    setPlayers(initialPlayers);
    setPresetFines(loadedPresets);
    setRoles(loadedRoles);
    setSettings(loadedSettings);
    setPasswords(loadedPasswords);

    storage.save('players', initialPlayers);

    syncFromCloud();

    const subscription = subscribeToCloudChanges(() => {
      syncFromCloud(true); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const syncFromCloud = async (silent = false) => {
    if (!silent) setIsSyncing(true);
    setSyncError(false);

    try {
      const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings, cloudPassItems] = (await Promise.all([
        cloudFetchAll('fine'),
        cloudFetchAll('player'),
        cloudFetchAll('preset'),
        cloudFetchAll('role'),
        cloudFetchAll('settings'),
        cloudFetchAll('password_item')
      ])) as [FineEntry[], Player[], PresetFine[], RoleDefinition[], any[], any[]];

      // --- SIKKER PASSORD-MERGING (Fix for overstyring) ---
      setPasswords(prevLocalPasswords => {
        const merged = { ...prevLocalPasswords };
        cloudPassItems.forEach((p: any) => {
          // Kun overskriv hvis vi ikke har gjort en lokal endring nylig (enkel merge)
          merged[p.playerId] = p.password;
        });
        storage.save('passwords', merged);
        return merged;
      });

      // --- SMART SPILLER-MERGING (Anti-massesletting) ---
      setPlayers(prevLocalPlayers => {
        if (cloudPlayers.length === 0) return prevLocalPlayers;

        const mergedMap = new Map<string, Player>();
        DEFAULT_PLAYERS.forEach(p => mergedMap.set(p.id, p));
        prevLocalPlayers.forEach(p => mergedMap.set(p.id, p));

        // Sjekk om skyen mangler unormalt mange spillere
        if (cloudPlayers.length < prevLocalPlayers.length) {
            const diff = prevLocalPlayers.length - cloudPlayers.length;
            if (diff > 1) {
                console.warn(`Sky-synk blokkert: Mangler ${diff} spillere i skyen. Bevarer lokal liste.`);
                return prevLocalPlayers;
            }
        }

        cloudPlayers.forEach(cp => mergedMap.set(cp.id, cp));
        const finalPlayers = Array.from(mergedMap.values());
        storage.save('players', finalPlayers);
        return finalPlayers;
      });

      // Bøter
      setFines(prevLocalFines => {
        const now = Date.now();
        const PENDING_UPLOAD_THRESHOLD = 15000;
        const cloudMap = new Map(cloudFines.map(f => [f.id, f]));
        const merged = prevLocalFines.filter(lf => cloudMap.has(lf.id) || (now - lf.timestamp) < PENDING_UPLOAD_THRESHOLD);
        cloudFines.forEach(cf => { if (!merged.find(m => m.id === cf.id)) merged.push(cf); });
        storage.save('fines', merged);
        return [...merged];
      });

      if (cloudPresets.length > 0) { setPresetFines(cloudPresets); storage.save('presets', cloudPresets); }
      if (cloudRoles.length > 0) { setRoles(cloudRoles); storage.save('roles', cloudRoles); }

      const settingsMap: Record<string, UserSettings> = {};
      cloudSettings.forEach((s: any) => settingsMap[s.playerId] = s);
      setSettings(settingsMap);

      if (!silent) triggerToast("Synkronisert");
    } catch (error) {
      console.error("Sync failed:", error);
      setSyncError(true);
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings, newPassword?: string) => {
    // 1. Oppdater lokal tilstand umiddelbart
    const updatedSettings = { ...settings, [playerId]: newSettings };
    setSettings(updatedSettings);
    storage.save('settings', updatedSettings);

    if (newPassword) {
        const updatedPass = { ...passwords, [playerId]: newPassword };
        setPasswords(updatedPass);
        storage.save('passwords', updatedPass);
    }

    // 2. Send til skyen
    try {
        await cloudSave('settings', playerId, { ...newSettings, playerId });
        if (newPassword) {
            await cloudSave('password_item', playerId, { playerId, password: newPassword });
        }
        triggerToast("Lagret i skyen");
    } catch (e) {
        triggerErrorToast("Kunne ikke lagre i skyen, men lagret lokalt.");
    }
  };

  const saveFine = async (fine: FineEntry) => {
    setFines(prev => {
      const newList = prev.find(f => f.id === fine.id) ? prev.map(f => f.id === fine.id ? fine : f) : [...prev, fine];
      storage.save('fines', newList);
      return newList;
    });
    await cloudSave('fine', fine.id, fine);
  };

  const deleteFine = async (id: string) => {
    setFines(prev => {
        const newList = prev.filter(f => f.id !== id);
        storage.save('fines', newList);
        return newList;
    });
    if (selectedFineId === id) { setSelectedFineId(null); setView('list'); }
    await cloudDelete('fine', id);
    triggerToast("Slettet");
  };

  const handleUpdatePlayer = async (playerId: string, updates: Partial<Player>) => {
    setPlayers(prev => {
        const updatedPlayers = prev.map(p => p.id === playerId ? { ...p, ...updates } : p);
        storage.save('players', updatedPlayers);
        const player = updatedPlayers.find(p => p.id === playerId);
        if (player) cloudSave('player', playerId, player);
        return updatedPlayers;
    });
    triggerToast("Spiller oppdatert");
  };

  const handleAddPlayer = async (name: string, position: string) => {
      const newPlayer: Player = { id: crypto.randomUUID(), name, position, systemRole: 'user' };
      const newList = [...players, newPlayer];
      setPlayers(newList);
      storage.save('players', newList);
      await cloudSave('player', newPlayer.id, newPlayer);
      triggerToast("Spiller lagt til");
  };

  const handleRemovePlayer = async (id: string) => {
      const newList = players.filter(p => p.id !== id);
      setPlayers(newList);
      storage.save('players', newList);
      await cloudDelete('player', id);
      triggerToast("Spiller fjernet");
  };

  const handleToggleAdmin = async (playerId: string) => {
      const updatedPlayers = players.map(p => {
          if (p.id === playerId) {
              return { ...p, systemRole: (p.systemRole === 'admin' ? 'user' : 'admin') as any };
          }
          return p;
      });
      setPlayers(updatedPlayers);
      storage.save('players', updatedPlayers);
      const player = updatedPlayers.find(p => p.id === playerId);
      if (player) await cloudSave('player', playerId, player);
      triggerToast("Rettigheter endret");
  };

  const handleAddPresetFine = async (label: string, amount: number, icon: string) => {
      const newPreset: PresetFine = { id: crypto.randomUUID(), label, amount, icon };
      const newList = [...presetFines, newPreset];
      setPresetFines(newList);
      storage.save('presets', newList);
      await cloudSave('preset', newPreset.id, newPreset);
      triggerToast("Bot lagt til");
  };

  const handleRemovePresetFine = async (id: string) => {
      const newList = presetFines.filter(p => p.id !== id);
      setPresetFines(newList);
      storage.save('presets', newList);
      await cloudDelete('preset', id);
      triggerToast("Bot fjernet");
  };

  const handleAddRole = async (name: string, color: string) => {
      const newRole: RoleDefinition = { id: crypto.randomUUID(), name, color };
      const newList = [...roles, newRole];
      setRoles(newList);
      storage.save('roles', newList);
      await cloudSave('role', newRole.id, newRole);
      triggerToast("Rolle lagt til");
  };

  const handleRemoveRole = async (id: string) => {
      const newList = roles.filter(r => r.id !== id);
      setRoles(newList);
      storage.save('roles', newList);
      await cloudDelete('role', id);
      triggerToast("Rolle fjernet");
  };

  const pushAllToCloud = async () => {
    setIsSyncing(true);
    try {
      await Promise.all([
        cloudSaveBulk('fine', fines),
        cloudSaveBulk('player', players),
        cloudSaveBulk('preset', presetFines),
        cloudSaveBulk('role', roles)
      ]);
      triggerToast("Alt lagret i skyen!");
    } catch (e) {
      triggerErrorToast("Tilkoblingsfeil.");
    } finally { setIsSyncing(false); }
  };

  const triggerToast = (msg: string) => {
    setShowSuccessToast(msg);
    setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const triggerErrorToast = (msg: string) => {
    setShowErrorToast(msg);
    setTimeout(() => setShowErrorToast(null), 3000);
  };

  const handleLogout = () => { setUser(null); setView('login'); setSelectedPlayerId(null); };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold">NHHI FC Botkassa våkner...</p>
      </div>
    );
  }

  const currentSelectedFine = fines.find(f => f.id === selectedFineId);
  const currentSelectedPlayer = players.find(p => p.id === (selectedPlayerId || user?.id));

  const getFineDetailPlayer = (fine: FineEntry) => {
      const p = players.find(x => x.id === fine.playerId);
      if (p) return p;
      return { id: fine.playerId, name: 'Slettet spiller', systemRole: 'user' as const };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase">{showSuccessToast}</span>
        </div>
      )}

      {showErrorToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <AlertTriangle size={16} />
          <span className="text-xs font-bold uppercase">{showErrorToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700 transition-colors"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <button onClick={() => syncFromCloud()} className={`p-2 rounded-full ${isSyncing ? 'animate-pulse text-amber-400' : 'text-green-400'}`}>
                                <Cloud size={14} />
                            </button>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView onLogin={(u) => { setUser(u); if(u.role === 'admin') setView('overview'); else { setSelectedPlayerId(u.id); setView('player'); } }} passwords={passwords} onSetPassword={handleUpdateSettings} players={players} />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? (
                currentSelectedFine ? (
                    <FineDetailView 
                        fine={currentSelectedFine} 
                        player={getFineDetailPlayer(currentSelectedFine)} 
                        currentUser={user} 
                        presetFines={presetFines} 
                        onBack={() => setView('list')} 
                        onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} 
                        onAddComment={(fid, t) => saveFine({...currentSelectedFine, comments: [...(currentSelectedFine.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]})}
                        onDeleteComment={(fid, cid) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).filter(c => c.id !== cid)})}
                        onToggleFineReaction={(fid, e) => { const r = currentSelectedFine.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...currentSelectedFine, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) }}
                        onToggleCommentReaction={(fid, cid, e) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).map(c => c.id === cid ? {...c, reactions: (c.reactions || []).findIndex(x => x.userId === user.id && x.emoji === e) > -1 ? (c.reactions || []).filter(x => !(x.userId === user.id && x.emoji === e)) : [...(c.reactions || []), {emoji: e, userId: user.id}]} : c)})}
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onAdminPay={(fid) => saveFine({...currentSelectedFine, status: 'paid', payRequest: undefined})} 
                    />
                ) : ( (setView('list'), null) )
            ) :
            view === 'player' ? (
                currentSelectedPlayer ? (
                    <PlayerProfileView 
                        player={currentSelectedPlayer} 
                        currentUserRole={user.role} 
                        currentUserId={user.id}
                        isOwnProfile={user.id === currentSelectedPlayer.id} 
                        fines={fines.filter(f => f.playerId === currentSelectedPlayer.id)} 
                        settings={settings[currentSelectedPlayer.id] || { pushEnabled: false }} 
                        presetFines={presetFines} 
                        roles={roles} 
                        onUpdateSettings={handleUpdateSettings} 
                        onUpdatePlayer={handleUpdatePlayer} 
                        onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} 
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} 
                        onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} 
                        onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} 
                        onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} 
                    />
                ) : ( (setView('overview'), null) )
            ) : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          hasPasswordSet={!!passwords[user.id]}
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={handleUpdateSettings} 
          onPushToCloud={pushAllToCloud}
          isSyncing={isSyncing}
          onCancel={() => setShowSettingsModal(false)} 
          onAddPlayer={handleAddPlayer}
          onRemovePlayer={handleRemovePlayer}
          onToggleAdmin={handleToggleAdmin}
          onAddPresetFine={handleAddPresetFine}
          onRemovePresetFine={handleRemovePresetFine}
          onAddRole={handleAddRole}
          onRemoveRole={handleRemoveRole}
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players, roles, presets: presetFines}} 
        />
      )}
    </div>
  );
};
export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ViewState, FineEntry, User, TimeFilter, UserSettings, Player, PresetFine, RoleDefinition } from './types';
import { DEFAULT_PLAYERS, PRESET_FINES as DEFAULT_PRESET_FINES, DEFAULT_ROLES } from './constants';
import { AddFineView } from './components/AddFineView';
import { StatsView } from './components/StatsView';
import { PlayerProfileView } from './components/PlayerProfileView';
import { LoginView } from './components/LoginView';
import { FineListView } from './components/FineListView';
import { NotificationsView } from './components/NotificationsView';
import { SettingsModal } from './components/SettingsModal';
import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { storage } from './services/storageService';
import { cloudSave, cloudDelete, cloudFetchAll, subscribeToCloudChanges, cloudSaveBulk } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);
  const [showErrorToast, setShowErrorToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [presetFines, setPresetFines] = useState<PresetFine[]>([]);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>([]);
  const [passwords, setPasswords] = useState<Record<string, string>>({});

  // Brukes for å hindre at skyen overskriver passordet rett etter en endring
  const lastPasswordUpdate = useRef<Record<string, number>>({});

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  // Initial load
  useEffect(() => {
    const loadedUser = storage.get<User | null>('session_user', null);
    const loadedFines = storage.get<FineEntry[]>('fines', []);
    const loadedPresets = storage.get<PresetFine[]>('presets', DEFAULT_PRESET_FINES);
    const loadedRoles = storage.get<RoleDefinition[]>('roles', DEFAULT_ROLES);
    const loadedSettings = storage.get<Record<string, UserSettings>>('settings', {});
    const loadedPasswords = storage.get<Record<string, string>>('passwords', {});

    // Spiller-oppsett
    const storedPlayers = storage.get<Player[]>('players', []);
    const initialPlayerMap = new Map<string, Player>();
    DEFAULT_PLAYERS.forEach(p => initialPlayerMap.set(p.id, p));
    storedPlayers.forEach(p => initialPlayerMap.set(p.id, p));
    const initialPlayers = Array.from(initialPlayerMap.values());

    setFines(loadedFines);
    setPlayers(initialPlayers);
    setPresetFines(loadedPresets);
    setRoles(loadedRoles);
    setSettings(loadedSettings);
    setPasswords(loadedPasswords);

    // Hvis vi fant en lagret sesjon, hopp rett inn
    if (loadedUser) {
      setUser(loadedUser);
      if (loadedUser.role === 'admin') setView('overview');
      else {
        setSelectedPlayerId(loadedUser.id);
        setView('player');
      }
    }

    storage.save('players', initialPlayers);

    syncFromCloud();

    const subscription = subscribeToCloudChanges(() => {
      syncFromCloud(true); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const syncFromCloud = async (silent = false) => {
    if (!silent) setIsSyncing(true);

    try {
      const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings, cloudPassItems] = (await Promise.all([
        cloudFetchAll('fine'),
        cloudFetchAll('player'),
        cloudFetchAll('preset'),
        cloudFetchAll('role'),
        cloudFetchAll('settings'),
        cloudFetchAll('password_item')
      ])) as [FineEntry[], Player[], PresetFine[], RoleDefinition[], any[], any[]];

      // SIKKER PASSORD-SYNCHRONISERING
      setPasswords(prevLocal => {
        const merged = { ...prevLocal };
        const now = Date.now();

        cloudPassItems.forEach((p: any) => {
          const lastLocalUpdate = lastPasswordUpdate.current[p.playerId] || 0;
          // Kun overskriv hvis det er mer enn 45 sekunder siden forrige lokale endring
          // Dette gir skyen tid til å "sette seg" uten race-conditions
          if (now - lastLocalUpdate > 45000) {
            merged[p.playerId] = p.password;
          }
        });

        storage.save('passwords', merged);
        return merged;
      });

      // SPILLER-MERGING
      setPlayers(prevLocal => {
        if (cloudPlayers.length === 0) return prevLocal;
        const mergedMap = new Map<string, Player>();
        DEFAULT_PLAYERS.forEach(p => mergedMap.set(p.id, p));
        prevLocal.forEach(p => mergedMap.set(p.id, p));

        if (cloudPlayers.length < prevLocal.length) {
            if (prevLocal.length - cloudPlayers.length > 1) return prevLocal;
        }

        cloudPlayers.forEach(cp => mergedMap.set(cp.id, cp));
        const final = Array.from(mergedMap.values());
        storage.save('players', final);
        return final;
      });

      // BØTER
      setFines(prevLocalFines => {
        const now = Date.now();
        const PENDING_UPLOAD_THRESHOLD = 15000;
        const cloudMap = new Map(cloudFines.map(f => [f.id, f]));
        const merged = prevLocalFines.filter(lf => cloudMap.has(lf.id) || (now - lf.timestamp) < PENDING_UPLOAD_THRESHOLD);
        cloudFines.forEach(cf => { if (!merged.find(m => m.id === cf.id)) merged.push(cf); });
        storage.save('fines', merged);
        return [...merged];
      });

      if (cloudPresets.length > 0) { setPresetFines(cloudPresets); storage.save('presets', cloudPresets); }
      if (cloudRoles.length > 0) { setRoles(cloudRoles); storage.save('roles', cloudRoles); }

      const settingsMap: Record<string, UserSettings> = {};
      cloudSettings.forEach((s: any) => settingsMap[s.playerId] = s);
      setSettings(settingsMap);

      if (!silent) triggerToast("Synkronisert");
    } catch (error) {
      console.error("Sync error:", error);
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings, newPassword?: string) => {
    // 1. Oppdater lokal state umiddelbart
    const updatedSettings = { ...settings, [playerId]: newSettings };
    setSettings(updatedSettings);
    storage.save('settings', updatedSettings);

    if (newPassword) {
        lastPasswordUpdate.current[playerId] = Date.now();
        const updatedPass = { ...passwords, [playerId]: newPassword };
        setPasswords(updatedPass);
        storage.save('passwords', updatedPass);
    }

    // 2. Send til skyen
    try {
        await cloudSave('settings', playerId, { ...newSettings, playerId });
        if (newPassword) {
            await cloudSave('password_item', playerId, { playerId, password: newPassword });
        }
        triggerToast("Lagret i skyen");
    } catch (e) {
        triggerErrorToast("Nettverksfeil - lagret lokalt.");
    }
  };

  const handleLogin = (u: User) => {
    setUser(u);
    storage.save('session_user', u); // LAGRE SESJON
    if(u.role === 'admin') setView('overview'); 
    else { setSelectedPlayerId(u.id); setView('player'); }
  };

  const handleLogout = () => { 
    setUser(null); 
    storage.remove('session_user'); // FJERN SESJON
    setView('login'); 
    setSelectedPlayerId(null); 
  };

  const saveFine = async (fine: FineEntry) => {
    setFines(prev => {
      const newList = prev.find(f => f.id === fine.id) ? prev.map(f => f.id === fine.id ? fine : f) : [...prev, fine];
      storage.save('fines', newList);
      return newList;
    });
    await cloudSave('fine', fine.id, fine);
  };

  const deleteFine = async (id: string) => {
    setFines(prev => {
        const newList = prev.filter(f => f.id !== id);
        storage.save('fines', newList);
        return newList;
    });
    if (selectedFineId === id) { setSelectedFineId(null); setView('list'); }
    await cloudDelete('fine', id);
    triggerToast("Slettet");
  };

  const handleUpdatePlayer = async (playerId: string, updates: Partial<Player>) => {
    setPlayers(prev => {
        const updatedPlayers = prev.map(p => p.id === playerId ? { ...p, ...updates } : p);
        storage.save('players', updatedPlayers);
        const player = updatedPlayers.find(p => p.id === playerId);
        if (player) cloudSave('player', playerId, player);
        return updatedPlayers;
    });
    triggerToast("Spiller oppdatert");
  };

  const handleAddPlayer = async (name: string, position: string) => {
      const newPlayer: Player = { id: crypto.randomUUID(), name, position, systemRole: 'user' };
      const newList = [...players, newPlayer];
      setPlayers(newList);
      storage.save('players', newList);
      await cloudSave('player', newPlayer.id, newPlayer);
      triggerToast("Spiller lagt til");
  };

  const handleRemovePlayer = async (id: string) => {
      const newList = players.filter(p => p.id !== id);
      setPlayers(newList);
      storage.save('players', newList);
      await cloudDelete('player', id);
      triggerToast("Spiller fjernet");
  };

  const handleToggleAdmin = async (playerId: string) => {
      const updatedPlayers = players.map(p => {
          if (p.id === playerId) {
              return { ...p, systemRole: (p.systemRole === 'admin' ? 'user' : 'admin') as any };
          }
          return p;
      });
      setPlayers(updatedPlayers);
      storage.save('players', updatedPlayers);
      const player = updatedPlayers.find(p => p.id === playerId);
      if (player) await cloudSave('player', playerId, player);
      triggerToast("Rettigheter endret");
  };

  const handleAddPresetFine = async (label: string, amount: number, icon: string) => {
      const newPreset: PresetFine = { id: crypto.randomUUID(), label, amount, icon };
      const newList = [...presetFines, newPreset];
      setPresetFines(newList);
      storage.save('presets', newList);
      await cloudSave('preset', newPreset.id, newPreset);
      triggerToast("Bot lagt til");
  };

  const handleRemovePresetFine = async (id: string) => {
      const newList = presetFines.filter(p => p.id !== id);
      setPresetFines(newList);
      storage.save('presets', newList);
      await cloudDelete('preset', id);
      triggerToast("Bot fjernet");
  };

  const handleAddRole = async (name: string, color: string) => {
      const newRole: RoleDefinition = { id: crypto.randomUUID(), name, color };
      const newList = [...roles, newRole];
      setRoles(newList);
      storage.save('roles', newList);
      await cloudSave('role', newRole.id, newRole);
      triggerToast("Rolle lagt til");
  };

  const handleRemoveRole = async (id: string) => {
      const newList = roles.filter(r => r.id !== id);
      setRoles(newList);
      storage.save('roles', newList);
      await cloudDelete('role', id);
      triggerToast("Rolle fjernet");
  };

  const pushAllToCloud = async () => {
    setIsSyncing(true);
    try {
      await Promise.all([
        cloudSaveBulk('fine', fines),
        cloudSaveBulk('player', players),
        cloudSaveBulk('preset', presetFines),
        cloudSaveBulk('role', roles)
      ]);
      triggerToast("Alt lagret i skyen!");
    } catch (e) {
      triggerErrorToast("Tilkoblingsfeil.");
    } finally { setIsSyncing(false); }
  };

  const triggerToast = (msg: string) => {
    setShowSuccessToast(msg);
    setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const triggerErrorToast = (msg: string) => {
    setShowErrorToast(msg);
    setTimeout(() => setShowErrorToast(null), 3000);
  };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold tracking-tight">NHHI FC Botkassa våkner...</p>
      </div>
    );
  }

  const currentSelectedFine = fines.find(f => f.id === selectedFineId);
  const currentSelectedPlayer = players.find(p => p.id === (selectedPlayerId || user?.id));

  const getFineDetailPlayer = (fine: FineEntry) => {
      const p = players.find(x => x.id === fine.playerId);
      if (p) return p;
      return { id: fine.playerId, name: 'Slettet spiller', systemRole: 'user' as const };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase">{showSuccessToast}</span>
        </div>
      )}

      {showErrorToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <AlertTriangle size={16} />
          <span className="text-xs font-bold uppercase">{showErrorToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700 transition-colors"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <button onClick={() => syncFromCloud()} className={`p-2 rounded-full ${isSyncing ? 'animate-pulse text-amber-400' : 'text-green-400'}`}>
                                <Cloud size={14} />
                            </button>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView onLogin={handleLogin} passwords={passwords} onSetPassword={handleUpdateSettings} players={players} />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? (
                currentSelectedFine ? (
                    <FineDetailView 
                        fine={currentSelectedFine} 
                        player={getFineDetailPlayer(currentSelectedFine)} 
                        currentUser={user} 
                        presetFines={presetFines} 
                        onBack={() => setView('list')} 
                        onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} 
                        onAddComment={(fid, t) => saveFine({...currentSelectedFine, comments: [...(currentSelectedFine.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]})}
                        onDeleteComment={(fid, cid) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).filter(c => c.id !== cid)})}
                        onToggleFineReaction={(fid, e) => { const r = currentSelectedFine.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...currentSelectedFine, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) }}
                        onToggleCommentReaction={(fid, cid, e) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).map(c => c.id === cid ? {...c, reactions: (c.reactions || []).findIndex(x => x.userId === user.id && x.emoji === e) > -1 ? (c.reactions || []).filter(x => !(x.userId === user.id && x.emoji === e)) : [...(c.reactions || []), {emoji: e, userId: user.id}]} : c)})}
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onAdminPay={(fid) => saveFine({...currentSelectedFine, status: 'paid', payRequest: undefined})} 
                    />
                ) : ( (setView('list'), null) )
            ) :
            view === 'player' ? (
                currentSelectedPlayer ? (
                    <PlayerProfileView 
                        player={currentSelectedPlayer} 
                        currentUserRole={user.role} 
                        currentUserId={user.id}
                        isOwnProfile={user.id === currentSelectedPlayer.id} 
                        fines={fines.filter(f => f.playerId === currentSelectedPlayer.id)} 
                        settings={settings[currentSelectedPlayer.id] || { pushEnabled: false }} 
                        presetFines={presetFines} 
                        roles={roles} 
                        onUpdateSettings={handleUpdateSettings} 
                        onUpdatePlayer={handleUpdatePlayer} 
                        onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} 
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} 
                        onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} 
                        onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} 
                        onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} 
                    />
                ) : ( (setView('overview'), null) )
            ) : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          hasPasswordSet={!!passwords[user.id]}
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={handleUpdateSettings} 
          onPushToCloud={pushAllToCloud}
          isSyncing={isSyncing}
          onCancel={() => setShowSettingsModal(false)} 
          onAddPlayer={handleAddPlayer}
          onRemovePlayer={handleRemovePlayer}
          onToggleAdmin={handleToggleAdmin}
          onAddPresetFine={handleAddPresetFine}
          onRemovePresetFine={handleRemovePresetFine}
          onAddRole={handleAddRole}
          onRemoveRole={handleRemoveRole}
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players, roles, presets: presetFines}} 
        />
      )}
    </div>
  );
};
export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { ViewState, FineEntry, User, TimeFilter, UserSettings, Player, PresetFine, RoleDefinition } from './types';
import { DEFAULT_PLAYERS, PRESET_FINES as DEFAULT_PRESET_FINES, DEFAULT_ROLES } from './constants';
import { AddFineView } from './components/AddFineView';
import { StatsView } from './components/StatsView';
import { PlayerProfileView } from './components/PlayerProfileView';
import { LoginView } from './components/LoginView';
import { FineListView } from './components/FineListView';
import { NotificationsView } from './components/NotificationsView';
import { SettingsModal } from './components/SettingsModal';
import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { storage } from './services/storageService';
import { cloudSave, cloudDelete, cloudFetchAll, subscribeToCloudChanges, cloudSaveBulk } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);
  const [showErrorToast, setShowErrorToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [presetFines, setPresetFines] = useState<PresetFine[]>([]);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>([]);
  const [passwords, setPasswords] = useState<Record<string, string>>({});

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  // Initial load
  useEffect(() => {
    const loadedUser = storage.get<User | null>('session_user', null);
    const loadedFines = storage.get<FineEntry[]>('fines', []);
    const loadedPresets = storage.get<PresetFine[]>('presets', DEFAULT_PRESET_FINES);
    const loadedRoles = storage.get<RoleDefinition[]>('roles', DEFAULT_ROLES);
    const loadedSettings = storage.get<Record<string, UserSettings>>('settings', {});
    const loadedPasswords = storage.get<Record<string, string>>('passwords', {});

    // Spiller-oppsett
    const storedPlayers = storage.get<Player[]>('players', []);
    const initialPlayerMap = new Map<string, Player>();
    DEFAULT_PLAYERS.forEach(p => initialPlayerMap.set(p.id, p));
    storedPlayers.forEach(p => initialPlayerMap.set(p.id, p));
    const initialPlayers = Array.from(initialPlayerMap.values());

    setFines(loadedFines);
    setPlayers(initialPlayers);
    setPresetFines(loadedPresets);
    setRoles(loadedRoles);
    setSettings(loadedSettings);
    setPasswords(loadedPasswords);

    if (loadedUser) {
      setUser(loadedUser);
      if (loadedUser.role === 'admin') setView('overview');
      else { setSelectedPlayerId(loadedUser.id); setView('player'); }
    }

    storage.save('players', initialPlayers);

    syncFromCloud();

    const subscription = subscribeToCloudChanges(() => {
      syncFromCloud(true); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const syncFromCloud = async (silent = false) => {
    if (!silent) setIsSyncing(true);

    try {
      const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings, cloudPassItems] = (await Promise.all([
        cloudFetchAll('fine'),
        cloudFetchAll('player'),
        cloudFetchAll('preset'),
        cloudFetchAll('role'),
        cloudFetchAll('settings'),
        cloudFetchAll('password_item')
      ])) as [FineEntry[], Player[], PresetFine[], RoleDefinition[], any[], any[]];

      // SIKKER PASSORD-MERGING (Viktig fix: bruker localStorage for tidsstempler)
      setPasswords(prevLocal => {
        const merged = { ...prevLocal };
        const now = Date.now();
        const lastUpdates = storage.get<Record<string, number>>('pass_updates', {});

        cloudPassItems.forEach((p: any) => {
          const lastLocalUpdate = lastUpdates[p.playerId] || 0;
          // Økt beskyttelse til 120 sekunder for å være helt sikker
          if (now - lastLocalUpdate > 120000) {
            merged[p.playerId] = p.password;
          } else {
            console.log(`Beskytter lokalt passord for ${p.playerId} mot overskriving fra skyen.`);
          }
        });

        storage.save('passwords', merged);
        return merged;
      });

      // SPILLER-MERGING
      setPlayers(prevLocal => {
        if (cloudPlayers.length === 0) return prevLocal;
        const mergedMap = new Map<string, Player>();
        DEFAULT_PLAYERS.forEach(p => mergedMap.set(p.id, p));
        prevLocal.forEach(p => mergedMap.set(p.id, p));

        if (cloudPlayers.length < prevLocal.length) {
            if (prevLocal.length - cloudPlayers.length > 1) return prevLocal;
        }

        cloudPlayers.forEach(cp => mergedMap.set(cp.id, cp));
        const final = Array.from(mergedMap.values());
        storage.save('players', final);
        return final;
      });

      // BØTER
      setFines(prevLocalFines => {
        const now = Date.now();
        const PENDING_UPLOAD_THRESHOLD = 15000;
        const cloudMap = new Map(cloudFines.map(f => [f.id, f]));
        const merged = prevLocalFines.filter(lf => cloudMap.has(lf.id) || (now - lf.timestamp) < PENDING_UPLOAD_THRESHOLD);
        cloudFines.forEach(cf => { if (!merged.find(m => m.id === cf.id)) merged.push(cf); });
        storage.save('fines', merged);
        return [...merged];
      });

      if (cloudPresets.length > 0) { setPresetFines(cloudPresets); storage.save('presets', cloudPresets); }
      if (cloudRoles.length > 0) { setRoles(cloudRoles); storage.save('roles', cloudRoles); }

      const settingsMap: Record<string, UserSettings> = {};
      cloudSettings.forEach((s: any) => settingsMap[s.playerId] = s);
      setSettings(settingsMap);

      if (!silent) triggerToast("Synkronisert");
    } catch (error) {
      console.error("Sync error:", error);
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings, newPassword?: string) => {
    // 1. Lagre lokalt FØRST
    const updatedSettings = { ...settings, [playerId]: newSettings };
    setSettings(updatedSettings);
    storage.save('settings', updatedSettings);

    if (newPassword) {
        // Lagre tidsstempel i localStorage slik at det overlever reload
        const lastUpdates = storage.get<Record<string, number>>('pass_updates', {});
        lastUpdates[playerId] = Date.now();
        storage.save('pass_updates', lastUpdates);

        const updatedPass = { ...passwords, [playerId]: newPassword };
        setPasswords(updatedPass);
        storage.save('passwords', updatedPass);
    }

    // 2. Send til skyen
    try {
        await cloudSave('settings', playerId, { ...newSettings, playerId });
        if (newPassword) {
            await cloudSave('password_item', playerId, { playerId, password: newPassword });
        }
        triggerToast("Lagret i skyen");
    } catch (e) {
        triggerErrorToast("Nettverksfeil - lagret kun lokalt.");
    }
  };

  const handleLogin = (u: User) => {
    setUser(u);
    storage.save('session_user', u);
    if(u.role === 'admin') setView('overview'); 
    else { setSelectedPlayerId(u.id); setView('player'); }
  };

  const handleLogout = () => { 
    setUser(null); 
    storage.remove('session_user');
    setView('login'); 
    setSelectedPlayerId(null); 
  };

  const saveFine = async (fine: FineEntry) => {
    setFines(prev => {
      const newList = prev.find(f => f.id === fine.id) ? prev.map(f => f.id === fine.id ? fine : f) : [...prev, fine];
      storage.save('fines', newList);
      return newList;
    });
    await cloudSave('fine', fine.id, fine);
  };

  const deleteFine = async (id: string) => {
    setFines(prev => {
        const newList = prev.filter(f => f.id !== id);
        storage.save('fines', newList);
        return newList;
    });
    if (selectedFineId === id) { setSelectedFineId(null); setView('list'); }
    await cloudDelete('fine', id);
    triggerToast("Slettet");
  };

  const handleUpdatePlayer = async (playerId: string, updates: Partial<Player>) => {
    setPlayers(prev => {
        const updatedPlayers = prev.map(p => p.id === playerId ? { ...p, ...updates } : p);
        storage.save('players', updatedPlayers);
        const player = updatedPlayers.find(p => p.id === playerId);
        if (player) cloudSave('player', playerId, player);
        return updatedPlayers;
    });
    triggerToast("Spiller oppdatert");
  };

  const handleAddPlayer = async (name: string, position: string) => {
      const newPlayer: Player = { id: crypto.randomUUID(), name, position, systemRole: 'user' };
      const newList = [...players, newPlayer];
      setPlayers(newList);
      storage.save('players', newList);
      await cloudSave('player', newPlayer.id, newPlayer);
      triggerToast("Spiller lagt til");
  };

  const handleRemovePlayer = async (id: string) => {
      const newList = players.filter(p => p.id !== id);
      setPlayers(newList);
      storage.save('players', newList);
      await cloudDelete('player', id);
      triggerToast("Spiller fjernet");
  };

  const handleToggleAdmin = async (playerId: string) => {
      const updatedPlayers = players.map(p => {
          if (p.id === playerId) {
              return { ...p, systemRole: (p.systemRole === 'admin' ? 'user' : 'admin') as any };
          }
          return p;
      });
      setPlayers(updatedPlayers);
      storage.save('players', updatedPlayers);
      const player = updatedPlayers.find(p => p.id === playerId);
      if (player) await cloudSave('player', playerId, player);
      triggerToast("Rettigheter endret");
  };

  const handleAddPresetFine = async (label: string, amount: number, icon: string) => {
      const newPreset: PresetFine = { id: crypto.randomUUID(), label, amount, icon };
      const newList = [...presetFines, newPreset];
      setPresetFines(newList);
      storage.save('presets', newList);
      await cloudSave('preset', newPreset.id, newPreset);
      triggerToast("Bot lagt til");
  };

  const handleRemovePresetFine = async (id: string) => {
      const newList = presetFines.filter(p => p.id !== id);
      setPresetFines(newList);
      storage.save('presets', newList);
      await cloudDelete('preset', id);
      triggerToast("Bot fjernet");
  };

  const handleAddRole = async (name: string, color: string) => {
      const newRole: RoleDefinition = { id: crypto.randomUUID(), name, color };
      const newList = [...roles, newRole];
      setRoles(newList);
      storage.save('roles', newList);
      await cloudSave('role', newRole.id, newRole);
      triggerToast("Rolle lagt til");
  };

  const handleRemoveRole = async (id: string) => {
      const newList = roles.filter(r => r.id !== id);
      setRoles(newList);
      storage.save('roles', newList);
      await cloudDelete('role', id);
      triggerToast("Rolle fjernet");
  };

  const pushAllToCloud = async () => {
    setIsSyncing(true);
    try {
      await Promise.all([
        cloudSaveBulk('fine', fines),
        cloudSaveBulk('player', players),
        cloudSaveBulk('preset', presetFines),
        cloudSaveBulk('role', roles)
      ]);
      triggerToast("Alt lagret i skyen!");
    } catch (e) {
      triggerErrorToast("Tilkoblingsfeil.");
    } finally { setIsSyncing(false); }
  };

  const triggerToast = (msg: string) => {
    setShowSuccessToast(msg);
    setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const triggerErrorToast = (msg: string) => {
    setShowErrorToast(msg);
    setTimeout(() => setShowErrorToast(null), 3000);
  };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold tracking-tight">NHHI FC Botkassa våkner...</p>
      </div>
    );
  }

  const currentSelectedFine = fines.find(f => f.id === selectedFineId);
  const currentSelectedPlayer = players.find(p => p.id === (selectedPlayerId || user?.id));

  const getFineDetailPlayer = (fine: FineEntry) => {
      const p = players.find(x => x.id === fine.playerId);
      if (p) return p;
      return { id: fine.playerId, name: 'Slettet spiller', systemRole: 'user' as const };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase">{showSuccessToast}</span>
        </div>
      )}

      {showErrorToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <AlertTriangle size={16} />
          <span className="text-xs font-bold uppercase">{showErrorToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700 transition-colors"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <button onClick={() => syncFromCloud()} className={`p-2 rounded-full ${isSyncing ? 'animate-pulse text-amber-400' : 'text-green-400'}`}>
                                <Cloud size={14} />
                            </button>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView onLogin={handleLogin} passwords={passwords} onSetPassword={handleUpdateSettings} players={players} />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? (
                currentSelectedFine ? (
                    <FineDetailView 
                        fine={currentSelectedFine} 
                        player={getFineDetailPlayer(currentSelectedFine)} 
                        currentUser={user} 
                        presetFines={presetFines} 
                        onBack={() => setView('list')} 
                        onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} 
                        onAddComment={(fid, t) => saveFine({...currentSelectedFine, comments: [...(currentSelectedFine.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]})}
                        onDeleteComment={(fid, cid) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).filter(c => c.id !== cid)})}
                        onToggleFineReaction={(fid, e) => { const r = currentSelectedFine.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...currentSelectedFine, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) }}
                        onToggleCommentReaction={(fid, cid, e) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).map(c => c.id === cid ? {...c, reactions: (c.reactions || []).findIndex(x => x.userId === user.id && x.emoji === e) > -1 ? (c.reactions || []).filter(x => !(x.userId === user.id && x.emoji === e)) : [...(c.reactions || []), {emoji: e, userId: user.id}]} : c)})}
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onAdminPay={(fid) => saveFine({...currentSelectedFine, status: 'paid', payRequest: undefined})} 
                    />
                ) : ( (setView('list'), null) )
            ) :
            view === 'player' ? (
                currentSelectedPlayer ? (
                    <PlayerProfileView 
                        player={currentSelectedPlayer} 
                        currentUserRole={user.role} 
                        currentUserId={user.id}
                        isOwnProfile={user.id === currentSelectedPlayer.id} 
                        fines={fines.filter(f => f.playerId === currentSelectedPlayer.id)} 
                        settings={settings[currentSelectedPlayer.id] || { pushEnabled: false }} 
                        presetFines={presetFines} 
                        roles={roles} 
                        onUpdateSettings={handleUpdateSettings} 
                        onUpdatePlayer={handleUpdatePlayer} 
                        onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} 
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} 
                        onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} 
                        onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} 
                        onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} 
                    />
                ) : ( (setView('overview'), null) )
            ) : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          hasPasswordSet={!!passwords[user.id]}
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={handleUpdateSettings} 
          onPushToCloud={pushAllToCloud}
          isSyncing={isSyncing}
          onCancel={() => setShowSettingsModal(false)} 
          onAddPlayer={handleAddPlayer}
          onRemovePlayer={handleRemovePlayer}
          onToggleAdmin={handleToggleAdmin}
          onAddPresetFine={handleAddPresetFine}
          onRemovePresetFine={handleRemovePresetFine}
          onAddRole={handleAddRole}
          onRemoveRole={handleRemoveRole}
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players, roles, presets: presetFines}} 
        />
      )}
    </div>
  );
};
export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Player, User } from '../types';
import { User as UserIcon, Shield, Search, Lock, ChevronLeft, ArrowRight, Loader2, AlertCircle } from 'lucide-react';
import { Button } from './Button';

interface LoginViewProps {
  onLogin: (user: User) => void;
  passwords: Record<string, string>;
  onSetPassword: (playerId: string, pass: string) => void;
  players: Player[];
}

export const LoginView: React.FC<LoginViewProps> = ({ onLogin, passwords, players }) => {
  const [query, setQuery] = useState('');
  const [selectedPlayer, setSelectedPlayer] = useState<Player | null>(null);
  const [password, setPassword] = useState('');
  const [isVerifying, setIsVerifying] = useState(false);
  const [error, setError] = useState('');
  const passwordInputRef = useRef<HTMLInputElement>(null);

  const DEFAULT_PASSWORD = '1234';

  useEffect(() => {
    if (selectedPlayer && passwordInputRef.current) {
        passwordInputRef.current.focus();
    }
  }, [selectedPlayer]);

  const filteredPlayers = players.filter(p => 
    p.name.toLowerCase().includes(query.toLowerCase())
  );

  const handlePlayerClick = (player: Player) => {
      setSelectedPlayer(player);
      setPassword('');
      setError('');
  };

  const handleSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!selectedPlayer) return;

      setIsVerifying(true);
      setError('');

      await new Promise(r => setTimeout(r, 600));

      const correctPassword = passwords[selectedPlayer.id] || DEFAULT_PASSWORD;

      if (password === correctPassword) {
          onLogin({ 
            id: selectedPlayer.id, 
            name: selectedPlayer.name, 
            role: selectedPlayer.systemRole 
          });
      } else {
          setError('Feil passord. Prøv 1234 hvis du er ny.');
          setPassword('');
          if (passwordInputRef.current) passwordInputRef.current.focus();
      }

      setIsVerifying(false);
  };

  if (selectedPlayer) {
      return (
        <div className="flex flex-col items-center justify-center min-h-screen px-4 py-12">
             <div className={`bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm text-center border border-slate-100 animate-in fade-in slide-in-from-right-4 duration-300 relative ${error ? 'animate-shake' : ''}`}>
                <button 
                    onClick={() => setSelectedPlayer(null)}
                    className="absolute top-8 left-8 p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full transition-colors"
                >
                    <ChevronLeft size={24} />
                </button>

                <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600 shadow-sm mt-4">
                     <UserIcon size={32} />
                </div>

                <h2 className="text-xl font-bold text-slate-900 mb-1">{selectedPlayer.name}</h2>
                <p className="text-slate-500 text-sm mb-8">
                    Logg inn med ditt passord
                </p>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="relative">
                        <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                        <input
                            ref={passwordInputRef}
                            type="password"
                            value={password}
                            onChange={(e) => {
                                setPassword(e.target.value);
                                if(error) setError('');
                            }}
                            placeholder="Passord (f.eks 1234)"
                            className={`w-full pl-9 pr-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 outline-none text-slate-900 transition-all ${
                                error 
                                ? 'border-red-300 focus:ring-red-200 bg-red-50/30' 
                                : 'border-slate-200 focus:ring-blue-500'
                            }`}
                        />
                    </div>

                    {error && (
                        <div className="flex items-center justify-center text-xs text-red-600 font-bold animate-in fade-in slide-in-from-top-1">
                            <AlertCircle size={12} className="mr-1" />
                            {error}
                        </div>
                    )}

                    <Button type="submit" fullWidth disabled={isVerifying || !password}>
                        {isVerifying ? (
                            <Loader2 className="animate-spin w-5 h-5" />
                        ) : (
                            <>
                                Logg inn <ArrowRight size={16} className="ml-2" />
                            </>
                        )}
                    </Button>
                </form>
             </div>
        </div>
      );
  }

  return (
    <div className="flex flex-col items-center justify-center min-h-screen px-4 py-12">
      <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm text-center border border-slate-100 animate-in fade-in zoom-in duration-300 relative">

        <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 text-white shadow-lg rotate-3">
          <Shield size={30} />
        </div>

        <h1 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">NHHI FC</h1>
        <p className="text-slate-400 text-xs mb-8 font-bold uppercase tracking-widest">Botkassa</p>

        <div className="relative mb-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
          <input 
            type="text"
            placeholder="Søk navn..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="w-full pl-9 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-slate-900"
          />
        </div>

        <div className="space-y-2 max-h-[40vh] overflow-y-auto pr-2 no-scrollbar">
          {filteredPlayers.map(player => (
            <button
              key={player.id}
              onClick={() => handlePlayerClick(player)}
              className="w-full flex items-center p-3 hover:bg-blue-50 border border-slate-100 rounded-2xl transition-all group active:scale-95"
            >
              <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">
                <UserIcon size={16} />
              </div>
              <div className="text-left">
                <div className="font-bold text-slate-800 text-sm">{player.name}</div>
                <div className="text-[10px] text-slate-400 uppercase font-black tracking-widest">
                  {player.customRole || player.position || 'Spiller'}
                </div>
              </div>
            </button>
          ))}
          {filteredPlayers.length === 0 && (
            <p className="text-slate-400 text-xs py-4 italic">Ingen spillere funnet</p>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ViewState, FineEntry, User, TimeFilter, UserSettings, Player, PresetFine, RoleDefinition } from './types';
import { DEFAULT_PLAYERS, PRESET_FINES as DEFAULT_PRESET_FINES, DEFAULT_ROLES } from './constants';
import { AddFineView } from './components/AddFineView';
import { StatsView } from './components/StatsView';
import { PlayerProfileView } from './components/PlayerProfileView';
import { LoginView } from './components/LoginView';
import { FineListView } from './components/FineListView';
import { NotificationsView } from './components/NotificationsView';
import { SettingsModal } from './components/SettingsModal';
import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { storage } from './services/storageService';
import { cloudSave, cloudDelete, cloudFetchAll, subscribeToCloudChanges, cloudSaveBulk } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);
  const [showErrorToast, setShowErrorToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [presetFines, setPresetFines] = useState<PresetFine[]>([]);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>([]);
  const [passwords, setPasswords] = useState<Record<string, string>>({});

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  // Initial load fra lokal lagring (vår kilde til sannhet ved oppstart)
  useEffect(() => {
    const loadedUser = storage.get<User | null>('session_user', null);
    const loadedFines = storage.get<FineEntry[]>('fines', []);
    const loadedPresets = storage.get<PresetFine[]>('presets', DEFAULT_PRESET_FINES);
    const loadedRoles = storage.get<RoleDefinition[]>('roles', DEFAULT_ROLES);
    const loadedSettings = storage.get<Record<string, UserSettings>>('settings', {});
    const loadedPasswords = storage.get<Record<string, string>>('passwords', {});

    // Sørg for at vi alltid har med standard-spillerne
    const storedPlayers = storage.get<Player[]>('players', []);
    const playerMap = new Map<string, Player>();
    DEFAULT_PLAYERS.forEach(p => playerMap.set(p.id, p));
    storedPlayers.forEach(p => playerMap.set(p.id, p));
    const initialPlayers = Array.from(playerMap.values());

    setFines(loadedFines);
    setPlayers(initialPlayers);
    setPresetFines(loadedPresets);
    setRoles(loadedRoles);
    setSettings(loadedSettings);
    setPasswords(loadedPasswords);

    if (loadedUser) {
      setUser(loadedUser);
      if (loadedUser.role === 'admin') setView('overview');
      else { setSelectedPlayerId(loadedUser.id); setView('player'); }
    }

    storage.save('players', initialPlayers);

    // Start synkronisering
    syncFromCloud();

    const subscription = subscribeToCloudChanges(() => {
      syncFromCloud(true); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const syncFromCloud = async (silent = false) => {
    if (!silent) setIsSyncing(true);

    try {
      const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings, cloudPassItems] = (await Promise.all([
        cloudFetchAll('fine'),
        cloudFetchAll('player'),
        cloudFetchAll('preset'),
        cloudFetchAll('role'),
        cloudFetchAll('settings'),
        cloudFetchAll('password_item')
      ])) as [FineEntry[], Player[], PresetFine[], RoleDefinition[], any[], any[]];

      // --- SIKKER PASSORD-SYNK (v4 - "Local Master") ---
      setPasswords(prevLocal => {
        const merged = { ...prevLocal };
        const now = Date.now();
        const lastUpdates = storage.get<Record<string, number>>('pass_updates', {});

        cloudPassItems.forEach((p: any) => {
          const localPass = prevLocal[p.playerId];
          const cloudPass = p.password;
          const lastLocalUpdate = lastUpdates[p.playerId] || 0;

          // LOGIKK: 
          // 1. Hvis vi har endret passord lokalt nylig (< 2 min), stol 100% på lokal kopi.
          // 2. Hvis skyen prøver å sende oss '1234', men vi har noe annet lokalt, ignorer skyen (hindrer reset-bug).
          // 3. Ellers, oppdater hvis verdiene er forskjellige.

          const isRecentlyUpdatedLocally = (now - lastLocalUpdate < 120000);
          const isCloudResettingToDefault = (cloudPass === '1234' && localPass && localPass !== '1234');

          if (!isRecentlyUpdatedLocally && !isCloudResettingToDefault) {
            merged[p.playerId] = cloudPass;
          }
        });

        storage.save('passwords', merged);
        return merged;
      });

      // --- ROBUST SPILLER-SYNK (Anti-tømming) ---
      setPlayers(prevLocal => {
        const mergedMap = new Map<string, Player>();
        // 1. Alltid ha med defaults
        DEFAULT_PLAYERS.forEach(p => mergedMap.set(p.id, p));
        // 2. Legg til det vi har lokalt
        prevLocal.forEach(p => mergedMap.set(p.id, p));
        // 3. Oppdater/legg til fra skyen (men slett aldri fra lokal liste her)
        cloudPlayers.forEach(cp => mergedMap.set(cp.id, cp));

        const final = Array.from(mergedMap.values());
        storage.save('players', final);
        return final;
      });

      // --- BØTER ---
      setFines(prevLocal => {
        const now = Date.now();
        const cloudMap = new Map(cloudFines.map(f => [f.id, f]));
        // Behold lokale bøter som er nye (ikke rukket å synke) eller som finnes i skyen
        const merged = prevLocal.filter(lf => cloudMap.has(lf.id) || (now - lf.timestamp) < 30000);
        cloudFines.forEach(cf => { if (!merged.find(m => m.id === cf.id)) merged.push(cf); });
        storage.save('fines', merged);
        return [...merged];
      });

      if (cloudPresets.length > 0) { setPresetFines(cloudPresets); storage.save('presets', cloudPresets); }
      if (cloudRoles.length > 0) { setRoles(cloudRoles); storage.save('roles', cloudRoles); }

      const settingsMap: Record<string, UserSettings> = {};
      cloudSettings.forEach((s: any) => settingsMap[s.playerId] = s);
      setSettings(settingsMap);

      if (!silent) triggerToast("Synkronisert");
    } catch (error) {
      console.error("Sync error:", error);
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings, newPassword?: string) => {
    // 1. Lagre lokalt ØYEBLIKKELIG for å sikre "Local Authority"
    const updatedSettings = { ...settings, [playerId]: newSettings };
    setSettings(updatedSettings);
    storage.save('settings', updatedSettings);

    if (newPassword) {
        // Sett tidsstempel for beskyttelse
        const lastUpdates = storage.get<Record<string, number>>('pass_updates', {});
        lastUpdates[playerId] = Date.now();
        storage.save('pass_updates', lastUpdates);

        // Lagre selve passordet
        const updatedPass = { ...passwords, [playerId]: newPassword };
        setPasswords(updatedPass);
        storage.save('passwords', updatedPass);

        console.log(`Lokal autoritet satt for passord til ${playerId}. Beskyttet i 120s.`);
    }

    // 2. Forsøk å sende til skyen i bakgrunnen
    try {
        await cloudSave('settings', playerId, { ...newSettings, playerId });
        if (newPassword) {
            await cloudSave('password_item', playerId, { playerId, password: newPassword });
        }
        triggerToast("Lagret i skyen");
    } catch (e) {
        triggerErrorToast("Kunne ikke nå skyen, men lagret på telefonen din.");
    }
  };

  const handleLogin = (u: User) => {
    setUser(u);
    storage.save('session_user', u);
    if(u.role === 'admin') setView('overview'); 
    else { setSelectedPlayerId(u.id); setView('player'); }
  };

  const handleLogout = () => { 
    setUser(null); 
    storage.remove('session_user');
    setView('login'); 
    setSelectedPlayerId(null); 
  };

  const saveFine = async (fine: FineEntry) => {
    setFines(prev => {
      const newList = prev.find(f => f.id === fine.id) ? prev.map(f => f.id === fine.id ? fine : f) : [...prev, fine];
      storage.save('fines', newList);
      return newList;
    });
    await cloudSave('fine', fine.id, fine);
  };

  const deleteFine = async (id: string) => {
    setFines(prev => {
        const newList = prev.filter(f => f.id !== id);
        storage.save('fines', newList);
        return newList;
    });
    if (selectedFineId === id) { setSelectedFineId(null); setView('list'); }
    await cloudDelete('fine', id);
    triggerToast("Slettet");
  };

  const handleUpdatePlayer = async (playerId: string, updates: Partial<Player>) => {
    setPlayers(prev => {
        const updatedPlayers = prev.map(p => p.id === playerId ? { ...p, ...updates } : p);
        storage.save('players', updatedPlayers);
        const player = updatedPlayers.find(p => p.id === playerId);
        if (player) cloudSave('player', playerId, player);
        return updatedPlayers;
    });
    triggerToast("Spiller oppdatert");
  };

  const handleAddPlayer = async (name: string, position: string) => {
      const newPlayer: Player = { id: crypto.randomUUID(), name, position, systemRole: 'user' };
      const newList = [...players, newPlayer];
      setPlayers(newList);
      storage.save('players', newList);
      await cloudSave('player', newPlayer.id, newPlayer);
      triggerToast("Spiller lagt til");
  };

  const handleRemovePlayer = async (id: string) => {
      const newList = players.filter(p => p.id !== id);
      setPlayers(newList);
      storage.save('players', newList);
      await cloudDelete('player', id);
      triggerToast("Spiller fjernet");
  };

  const handleToggleAdmin = async (playerId: string) => {
      const updatedPlayers = players.map(p => {
          if (p.id === playerId) {
              return { ...p, systemRole: (p.systemRole === 'admin' ? 'user' : 'admin') as any };
          }
          return p;
      });
      setPlayers(updatedPlayers);
      storage.save('players', updatedPlayers);
      const player = updatedPlayers.find(p => p.id === playerId);
      if (player) await cloudSave('player', playerId, player);
      triggerToast("Rettigheter endret");
  };

  const handleAddPresetFine = async (label: string, amount: number, icon: string) => {
      const newPreset: PresetFine = { id: crypto.randomUUID(), label, amount, icon };
      const newList = [...presetFines, newPreset];
      setPresetFines(newList);
      storage.save('presets', newList);
      await cloudSave('preset', newPreset.id, newPreset);
      triggerToast("Bot lagt til");
  };

  const handleRemovePresetFine = async (id: string) => {
      const newList = presetFines.filter(p => p.id !== id);
      setPresetFines(newList);
      storage.save('presets', newList);
      await cloudDelete('preset', id);
      triggerToast("Bot fjernet");
  };

  const handleAddRole = async (name: string, color: string) => {
      const newRole: RoleDefinition = { id: crypto.randomUUID(), name, color };
      const newList = [...roles, newRole];
      setRoles(newList);
      storage.save('roles', newList);
      await cloudSave('role', newRole.id, newRole);
      triggerToast("Rolle lagt til");
  };

  const handleRemoveRole = async (id: string) => {
      const newList = roles.filter(r => r.id !== id);
      setRoles(newList);
      storage.save('roles', newList);
      await cloudDelete('role', id);
      triggerToast("Rolle fjernet");
  };

  const pushAllToCloud = async () => {
    setIsSyncing(true);
    try {
      await Promise.all([
        cloudSaveBulk('fine', fines),
        cloudSaveBulk('player', players),
        cloudSaveBulk('preset', presetFines),
        cloudSaveBulk('role', roles)
      ]);
      triggerToast("Alt lagret i skyen!");
    } catch (e) {
      triggerErrorToast("Tilkoblingsfeil.");
    } finally { setIsSyncing(false); }
  };

  const triggerToast = (msg: string) => {
    setShowSuccessToast(msg);
    setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const triggerErrorToast = (msg: string) => {
    setShowErrorToast(msg);
    setTimeout(() => setShowErrorToast(null), 3000);
  };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold tracking-tight">NHHI FC Botkassa våkner...</p>
      </div>
    );
  }

  const currentSelectedFine = fines.find(f => f.id === selectedFineId);
  const currentSelectedPlayer = players.find(p => p.id === (selectedPlayerId || user?.id));

  const getFineDetailPlayer = (fine: FineEntry) => {
      const p = players.find(x => x.id === fine.playerId);
      if (p) return p;
      return { id: fine.playerId, name: 'Slettet spiller', systemRole: 'user' as const };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase">{showSuccessToast}</span>
        </div>
      )}

      {showErrorToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <AlertTriangle size={16} />
          <span className="text-xs font-bold uppercase">{showErrorToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700 transition-colors"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <button onClick={() => syncFromCloud()} className={`p-2 rounded-full ${isSyncing ? 'animate-pulse text-amber-400' : 'text-green-400'}`}>
                                <Cloud size={14} />
                            </button>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView onLogin={handleLogin} passwords={passwords} onSetPassword={handleUpdateSettings} players={players} />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? (
                currentSelectedFine ? (
                    <FineDetailView 
                        fine={currentSelectedFine} 
                        player={getFineDetailPlayer(currentSelectedFine)} 
                        currentUser={user} 
                        presetFines={presetFines} 
                        onBack={() => setView('list')} 
                        onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} 
                        onAddComment={(fid, t) => saveFine({...currentSelectedFine, comments: [...(currentSelectedFine.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]})}
                        onDeleteComment={(fid, cid) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).filter(c => c.id !== cid)})}
                        onToggleFineReaction={(fid, e) => { const r = currentSelectedFine.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...currentSelectedFine, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) }}
                        onToggleCommentReaction={(fid, cid, e) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).map(c => c.id === cid ? {...c, reactions: (c.reactions || []).findIndex(x => x.userId === user.id && x.emoji === e) > -1 ? (c.reactions || []).filter(x => !(x.userId === user.id && x.emoji === e)) : [...(c.reactions || []), {emoji: e, userId: user.id}]} : c)})}
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onAdminPay={(fid) => saveFine({...currentSelectedFine, status: 'paid', payRequest: undefined})} 
                    />
                ) : ( (setView('list'), null) )
            ) :
            view === 'player' ? (
                currentSelectedPlayer ? (
                    <PlayerProfileView 
                        player={currentSelectedPlayer} 
                        currentUserRole={user.role} 
                        currentUserId={user.id}
                        isOwnProfile={user.id === currentSelectedPlayer.id} 
                        fines={fines.filter(f => f.playerId === currentSelectedPlayer.id)} 
                        settings={settings[currentSelectedPlayer.id] || { pushEnabled: false }} 
                        presetFines={presetFines} 
                        roles={roles} 
                        onUpdateSettings={handleUpdateSettings} 
                        onUpdatePlayer={handleUpdatePlayer} 
                        onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} 
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} 
                        onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} 
                        onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} 
                        onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} 
                    />
                ) : ( (setView('overview'), null) )
            ) : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          hasPasswordSet={!!passwords[user.id]}
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={handleUpdateSettings} 
          onPushToCloud={pushAllToCloud}
          isSyncing={isSyncing}
          onCancel={() => setShowSettingsModal(false)} 
          onAddPlayer={handleAddPlayer}
          onRemovePlayer={handleRemovePlayer}
          onToggleAdmin={handleToggleAdmin}
          onAddPresetFine={handleAddPresetFine}
          onRemovePresetFine={handleRemovePresetFine}
          onAddRole={handleAddRole}
          onRemoveRole={handleRemoveRole}
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players, roles, presets: presetFines}} 
        />
      )}
    </div>
  );
};
export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ViewState, FineEntry, User, TimeFilter, UserSettings, Player, PresetFine, RoleDefinition } from './types';
import { DEFAULT_PLAYERS, PRESET_FINES as DEFAULT_PRESET_FINES, DEFAULT_ROLES } from './constants';
import { AddFineView } from './components/AddFineView';
import { StatsView } from './components/StatsView';
import { PlayerProfileView } from './components/PlayerProfileView';
import { LoginView } from './components/LoginView';
import { FineListView } from './components/FineListView';
import { NotificationsView } from './components/NotificationsView';
import { SettingsModal } from './components/SettingsModal';
import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { storage } from './services/storageService';
import { cloudSave, cloudDelete, cloudFetchAll, subscribeToCloudChanges, cloudSaveBulk } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);
  const [showErrorToast, setShowErrorToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [presetFines, setPresetFines] = useState<PresetFine[]>([]);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>([]);
  const [passwords, setPasswords] = useState<Record<string, string>>({});

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  // 1. Last lokal data først (vår kilde til sannhet ved start)
  useEffect(() => {
    const loadedUser = storage.get<User | null>('session_user', null);
    const loadedFines = storage.get<FineEntry[]>('fines', []);
    const loadedPresets = storage.get<PresetFine[]>('presets', DEFAULT_PRESET_FINES);
    const loadedRoles = storage.get<RoleDefinition[]>('roles', DEFAULT_ROLES);
    const loadedSettings = storage.get<Record<string, UserSettings>>('settings', {});
    const loadedPasswords = storage.get<Record<string, string>>('passwords', {});

    const storedPlayers = storage.get<Player[]>('players', []);
    const playerMap = new Map<string, Player>();
    DEFAULT_PLAYERS.forEach(p => playerMap.set(p.id, p));
    storedPlayers.forEach(p => playerMap.set(p.id, p));
    const initialPlayers = Array.from(playerMap.values());

    setFines(loadedFines);
    setPlayers(initialPlayers);
    setPresetFines(loadedPresets);
    setRoles(loadedRoles);
    setSettings(loadedSettings);
    setPasswords(loadedPasswords);

    if (loadedUser) {
      setUser(loadedUser);
      if (loadedUser.role === 'admin') setView('overview');
      else { setSelectedPlayerId(loadedUser.id); setView('player'); }
    }

    storage.save('players', initialPlayers);

    // Kjør synkronisering ETTER at lokal state er satt
    setTimeout(() => {
        syncFromCloud();
    }, 100);

    const subscription = subscribeToCloudChanges(() => {
      syncFromCloud(true); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const syncFromCloud = async (silent = false) => {
    if (!silent) setIsSyncing(true);

    try {
      const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings, cloudPassItems] = (await Promise.all([
        cloudFetchAll('fine'),
        cloudFetchAll('player'),
        cloudFetchAll('preset'),
        cloudFetchAll('role'),
        cloudFetchAll('settings'),
        cloudFetchAll('password_item')
      ])) as [FineEntry[], Player[], PresetFine[], RoleDefinition[], any[], any[]];

      // --- SIKKER PASSORD-SYNK (v5) ---
      setPasswords(prevLocal => {
        const merged = { ...prevLocal };
        const now = Date.now();
        const lastUpdates = storage.get<Record<string, number>>('pass_updates', {});

        cloudPassItems.forEach((p: any) => {
          const localVal = prevLocal[p.playerId];
          const cloudVal = p.password;
          const lastLocalUpdate = lastUpdates[p.playerId] || 0;

          // HVIS vi nylig har oppdatert lokalt, ELLER skyen prøver å resette til 1234 når vi har noe annet: IGNORER SKYEN
          const isRecentlyUpdated = (now - lastLocalUpdate < 300000); // 5 minutter beskyttelse
          const isDefaultResetBug = (cloudVal === '1234' && localVal && localVal !== '1234');

          if (!isRecentlyUpdated && !isDefaultResetBug) {
             merged[p.playerId] = cloudVal;
          }
        });

        storage.save('passwords', merged);
        return merged;
      });

      // --- ROBUST SPILLER-SYNK (Nekter å slette ved tom respons) ---
      if (cloudPlayers && cloudPlayers.length > 0) {
          setPlayers(prevLocal => {
            const mergedMap = new Map<string, Player>();
            DEFAULT_PLAYERS.forEach(p => mergedMap.set(p.id, p));
            prevLocal.forEach(p => mergedMap.set(p.id, p));
            cloudPlayers.forEach(cp => mergedMap.set(cp.id, cp));

            const final = Array.from(mergedMap.values());
            storage.save('players', final);
            return final;
          });
      }

      // --- BØTER ---
      setFines(prevLocal => {
        const now = Date.now();
        const cloudMap = new Map(cloudFines.map(f => [f.id, f]));
        const merged = prevLocal.filter(lf => cloudMap.has(lf.id) || (now - lf.timestamp) < 60000);
        cloudFines.forEach(cf => { if (!merged.find(m => m.id === cf.id)) merged.push(cf); });
        storage.save('fines', merged);
        return [...merged];
      });

      if (cloudPresets.length > 0) { setPresetFines(cloudPresets); storage.save('presets', cloudPresets); }
      if (cloudRoles.length > 0) { setRoles(cloudRoles); storage.save('roles', cloudRoles); }

      const settingsMap: Record<string, UserSettings> = {};
      cloudSettings.forEach((s: any) => settingsMap[s.playerId] = s);
      setSettings(settingsMap);

      if (!silent) triggerToast("Synkronisert");
    } catch (error) {
      console.error("Sync error:", error);
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings, newPassword?: string) => {
    // 1. OPP-P-P-PDATER LOKALT ØYEBLIKKELIG (Functional update er nøkkelen her)
    setSettings(prev => {
        const updated = { ...prev, [playerId]: newSettings };
        storage.save('settings', updated);
        return updated;
    });

    if (newPassword) {
        // Sett tidsstempel i storage
        const lastUpdates = storage.get<Record<string, number>>('pass_updates', {});
        lastUpdates[playerId] = Date.now();
        storage.save('pass_updates', lastUpdates);

        setPasswords(prev => {
            const updated = { ...prev, [playerId]: newPassword };
            storage.save('passwords', updated);
            return updated;
        });
        console.log("Nytt passord satt lokalt for", playerId);
    }

    // 2. Send til skyen i bakgrunnen
    try {
        await cloudSave('settings', playerId, { ...newSettings, playerId });
        if (newPassword) {
            await cloudSave('password_item', playerId, { playerId, password: newPassword });
        }
        triggerToast("Lagret i skyen");
    } catch (e) {
        triggerErrorToast("Nettverksfeil - passordet er lagret lokalt på din telefon.");
    }
  };

  const handleLogin = (u: User) => {
    setUser(u);
    storage.save('session_user', u);
    if(u.role === 'admin') setView('overview'); 
    else { setSelectedPlayerId(u.id); setView('player'); }
  };

  const handleLogout = () => { 
    setUser(null); 
    storage.remove('session_user');
    setView('login'); 
    setSelectedPlayerId(null); 
  };

  const saveFine = async (fine: FineEntry) => {
    setFines(prev => {
      const newList = prev.find(f => f.id === fine.id) ? prev.map(f => f.id === fine.id ? fine : f) : [...prev, fine];
      storage.save('fines', newList);
      return newList;
    });
    await cloudSave('fine', fine.id, fine);
  };

  const deleteFine = async (id: string) => {
    setFines(prev => {
        const newList = prev.filter(f => f.id !== id);
        storage.save('fines', newList);
        return newList;
    });
    if (selectedFineId === id) { setSelectedFineId(null); setView('list'); }
    await cloudDelete('fine', id);
    triggerToast("Slettet");
  };

  const handleUpdatePlayer = async (playerId: string, updates: Partial<Player>) => {
    setPlayers(prev => {
        const updatedPlayers = prev.map(p => p.id === playerId ? { ...p, ...updates } : p);
        storage.save('players', updatedPlayers);
        const player = updatedPlayers.find(p => p.id === playerId);
        if (player) cloudSave('player', playerId, player);
        return updatedPlayers;
    });
    triggerToast("Spiller oppdatert");
  };

  const handleAddPlayer = async (name: string, position: string) => {
      const newPlayer: Player = { id: crypto.randomUUID(), name, position, systemRole: 'user' };
      setPlayers(prev => {
          const newList = [...prev, newPlayer];
          storage.save('players', newList);
          return newList;
      });
      await cloudSave('player', newPlayer.id, newPlayer);
      triggerToast("Spiller lagt til");
  };

  const handleRemovePlayer = async (id: string) => {
      setPlayers(prev => {
          const newList = prev.filter(p => p.id !== id);
          storage.save('players', newList);
          return newList;
      });
      await cloudDelete('player', id);
      triggerToast("Spiller fjernet");
  };

  const handleToggleAdmin = async (playerId: string) => {
      setPlayers(prev => {
          const updated = prev.map(p => p.id === playerId ? { ...p, systemRole: (p.systemRole === 'admin' ? 'user' : 'admin') as any } : p);
          storage.save('players', updated);
          const player = updated.find(p => p.id === playerId);
          if (player) cloudSave('player', playerId, player);
          return updated;
      });
      triggerToast("Rettigheter endret");
  };

  const handleAddPresetFine = async (label: string, amount: number, icon: string) => {
      const newPreset: PresetFine = { id: crypto.randomUUID(), label, amount, icon };
      setPresetFines(prev => {
          const newList = [...prev, newPreset];
          storage.save('presets', newList);
          return newList;
      });
      await cloudSave('preset', newPreset.id, newPreset);
      triggerToast("Bot lagt til");
  };

  const handleRemovePresetFine = async (id: string) => {
      setPresetFines(prev => {
          const newList = prev.filter(f => f.id !== id);
          storage.save('presets', newList);
          return newList;
      });
      await cloudDelete('preset', id);
      triggerToast("Bot fjernet");
  };

  const handleAddRole = async (name: string, color: string) => {
      const newRole: RoleDefinition = { id: crypto.randomUUID(), name, color };
      setRoles(prev => {
          const newList = [...prev, newRole];
          storage.save('roles', newList);
          return newList;
      });
      await cloudSave('role', newRole.id, newRole);
      triggerToast("Rolle lagt til");
  };

  const handleRemoveRole = async (id: string) => {
      setRoles(prev => {
          const newList = prev.filter(r => r.id !== id);
          storage.save('roles', newList);
          return newList;
      });
      await cloudDelete('role', id);
      triggerToast("Rolle fjernet");
  };

  const pushAllToCloud = async () => {
    setIsSyncing(true);
    try {
      await Promise.all([
        cloudSaveBulk('fine', fines),
        cloudSaveBulk('player', players),
        cloudSaveBulk('preset', presetFines),
        cloudSaveBulk('role', roles)
      ]);
      triggerToast("Alt lagret i skyen!");
    } catch (e) {
      triggerErrorToast("Tilkoblingsfeil.");
    } finally { setIsSyncing(false); }
  };

  const triggerToast = (msg: string) => {
    setShowSuccessToast(msg);
    setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const triggerErrorToast = (msg: string) => {
    setShowErrorToast(msg);
    setTimeout(() => setShowErrorToast(null), 3000);
  };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold tracking-tight">NHHI FC Botkassa våkner...</p>
      </div>
    );
  }

  const currentSelectedFine = fines.find(f => f.id === selectedFineId);
  const currentSelectedPlayer = players.find(p => p.id === (selectedPlayerId || user?.id));

  const getFineDetailPlayer = (fine: FineEntry) => {
      const p = players.find(x => x.id === fine.playerId);
      if (p) return p;
      return { id: fine.playerId, name: 'Slettet spiller', systemRole: 'user' as const };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase">{showSuccessToast}</span>
        </div>
      )}

      {showErrorToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <AlertTriangle size={16} />
          <span className="text-xs font-bold uppercase">{showErrorToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700 transition-colors"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <button onClick={() => syncFromCloud()} className={`p-2 rounded-full ${isSyncing ? 'animate-pulse text-amber-400' : 'text-green-400'}`}>
                                <Cloud size={14} />
                            </button>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView onLogin={handleLogin} passwords={passwords} onSetPassword={handleUpdateSettings} players={players} />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? (
                currentSelectedFine ? (
                    <FineDetailView 
                        fine={currentSelectedFine} 
                        player={getFineDetailPlayer(currentSelectedFine)} 
                        currentUser={user} 
                        presetFines={presetFines} 
                        onBack={() => setView('list')} 
                        onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} 
                        onAddComment={(fid, t) => saveFine({...currentSelectedFine, comments: [...(currentSelectedFine.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]})}
                        onDeleteComment={(fid, cid) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).filter(c => c.id !== cid)})}
                        onToggleFineReaction={(fid, e) => { const r = currentSelectedFine.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...currentSelectedFine, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) }}
                        onToggleCommentReaction={(fid, cid, e) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).map(c => c.id === cid ? {...c, reactions: (c.reactions || []).findIndex(x => x.userId === user.id && x.emoji === e) > -1 ? (c.reactions || []).filter(x => !(x.userId === user.id && x.emoji === e)) : [...(c.reactions || []), {emoji: e, userId: user.id}]} : c)})}
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onAdminPay={(fid) => saveFine({...currentSelectedFine, status: 'paid', payRequest: undefined})} 
                    />
                ) : ( (setView('list'), null) )
            ) :
            view === 'player' ? (
                currentSelectedPlayer ? (
                    <PlayerProfileView 
                        player={currentSelectedPlayer} 
                        currentUserRole={user.role} 
                        currentUserId={user.id}
                        isOwnProfile={user.id === currentSelectedPlayer.id} 
                        fines={fines.filter(f => f.playerId === currentSelectedPlayer.id)} 
                        settings={settings[currentSelectedPlayer.id] || { pushEnabled: false }} 
                        presetFines={presetFines} 
                        roles={roles} 
                        onUpdateSettings={handleUpdateSettings} 
                        onUpdatePlayer={handleUpdatePlayer} 
                        onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} 
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} 
                        onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} 
                        onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} 
                        onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} 
                    />
                ) : ( (setView('overview'), null) )
            ) : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          hasPasswordSet={!!passwords[user.id]}
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={handleUpdateSettings} 
          onPushToCloud={pushAllToCloud}
          isSyncing={isSyncing}
          onCancel={() => setShowSettingsModal(false)} 
          onAddPlayer={handleAddPlayer}
          onRemovePlayer={handleRemovePlayer}
          onToggleAdmin={handleToggleAdmin}
          onAddPresetFine={handleAddPresetFine}
          onRemovePresetFine={handleRemovePresetFine}
          onAddRole={handleAddRole}
          onRemoveRole={handleRemoveRole}
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players, roles, presets: presetFines}} 
        />
      )}
    </div>
  );
};
export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ViewState, FineEntry, User, TimeFilter, UserSettings, Player, PresetFine, RoleDefinition } from './types';
import { DEFAULT_PLAYERS, PRESET_FINES as DEFAULT_PRESET_FINES, DEFAULT_ROLES } from './constants';
import { AddFineView } from './components/AddFineView';
import { StatsView } from './components/StatsView';
import { PlayerProfileView } from './components/PlayerProfileView';
import { LoginView } from './components/LoginView';
import { FineListView } from './components/FineListView';
import { NotificationsView } from './components/NotificationsView';
import { SettingsModal } from './components/SettingsModal';
import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { storage } from './services/storageService';
import { cloudSave, cloudDelete, cloudFetchAll, subscribeToCloudChanges, cloudSaveBulk } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);
  const [showErrorToast, setShowErrorToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [presetFines, setPresetFines] = useState<PresetFine[]>([]);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>([]);

  // Passwords lagres nå som { [id]: { password: string, updatedAt: number } }
  const [passwords, setPasswords] = useState<Record<string, any>>({});

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  // Ref for å tracke når VI sist lagret noe, for å unngå race conditions
  const lastLocalSaveRef = useRef<number>(0);

  useEffect(() => {
    // 1. Last alt fra lokal disk først
    const loadedUser = storage.get<User | null>('session_user', null);
    const loadedFines = storage.get<FineEntry[]>('fines', []);
    const loadedPresets = storage.get<PresetFine[]>('presets', DEFAULT_PRESET_FINES);
    const loadedRoles = storage.get<RoleDefinition[]>('roles', DEFAULT_ROLES);
    const loadedSettings = storage.get<Record<string, UserSettings>>('settings', {});
    const loadedPasswords = storage.get<Record<string, any>>('passwords', {});

    const storedPlayers = storage.get<Player[]>('players', []);
    const playerMap = new Map<string, Player>();
    DEFAULT_PLAYERS.forEach(p => playerMap.set(p.id, p));
    storedPlayers.forEach(p => playerMap.set(p.id, p));

    setFines(loadedFines);
    setPlayers(Array.from(playerMap.values()));
    setPresetFines(loadedPresets);
    setRoles(loadedRoles);
    setSettings(loadedSettings);
    setPasswords(loadedPasswords);

    if (loadedUser) {
      setUser(loadedUser);
      if (loadedUser.role === 'admin') setView('overview');
      else { setSelectedPlayerId(loadedUser.id); setView('player'); }
    }

    // 2. Start sky-synk
    syncFromCloud();

    const subscription = subscribeToCloudChanges(() => {
      syncFromCloud(true); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const syncFromCloud = async (silent = false) => {
    // Hvis vi nettopp lagret noe selv (< 5 sek siden), vent med å synke for å unngå race conditions
    if (Date.now() - lastLocalSaveRef.current < 5000 && silent) return;

    if (!silent) setIsSyncing(true);

    try {
      const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings, cloudPassItems] = (await Promise.all([
        cloudFetchAll('fine'),
        cloudFetchAll('player'),
        cloudFetchAll('preset'),
        cloudFetchAll('role'),
        cloudFetchAll('settings'),
        cloudFetchAll('password_item')
      ])) as [FineEntry[], Player[], PresetFine[], RoleDefinition[], any[], any[]];

      // --- PASSORD-MERGING (Last-Write-Wins over flere enheter) ---
      setPasswords(prevLocal => {
        const merged = { ...prevLocal };
        cloudPassItems.forEach((p: any) => {
          const localItem = prevLocal[p.playerId];
          const cloudItem = p.value; // Supabase lagrer det i 'value' feltet

          // Hvis skyen har data, og enten:
          // a) Vi har ingenting lokalt
          // b) Skyen sin updatedAt er nyere enn vår lokale
          if (cloudItem && (!localItem || cloudItem.updatedAt > (localItem.updatedAt || 0))) {
            merged[p.playerId] = cloudItem;
          }
        });
        storage.save('passwords', merged);
        return merged;
      });

      // --- SPILLER-MERGING (Anti-sletting) ---
      if (cloudPlayers && cloudPlayers.length > 0) {
          setPlayers(prevLocal => {
            const mergedMap = new Map<string, Player>();
            DEFAULT_PLAYERS.forEach(p => mergedMap.set(p.id, p));
            prevLocal.forEach(p => mergedMap.set(p.id, p));
            cloudPlayers.forEach(cp => mergedMap.set(cp.id, cp));
            const final = Array.from(mergedMap.values());
            storage.save('players', final);
            return final;
          });
      }

      // --- BØTER ---
      setFines(prevLocal => {
        const now = Date.now();
        const cloudMap = new Map(cloudFines.map(f => [f.id, f]));
        const merged = prevLocal.filter(lf => cloudMap.has(lf.id) || (now - lf.timestamp) < 60000);
        cloudFines.forEach(cf => { if (!merged.find(m => m.id === cf.id)) merged.push(cf); });
        storage.save('fines', merged);
        return [...merged];
      });

      if (cloudPresets.length > 0) { setPresetFines(cloudPresets); storage.save('presets', cloudPresets); }
      if (cloudRoles.length > 0) { setRoles(cloudRoles); storage.save('roles', cloudRoles); }

      const settingsMap: Record<string, UserSettings> = {};
      cloudSettings.forEach((s: any) => settingsMap[s.playerId] = s);
      setSettings(settingsMap);

      if (!silent) triggerToast("Synkronisert");
    } catch (error) {
      console.error("Sync error:", error);
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings, newPassword?: string) => {
    lastLocalSaveRef.current = Date.now();

    // 1. Lagre alt lokalt FØRST
    setSettings(prev => {
        const updated = { ...prev, [playerId]: newSettings };
        storage.save('settings', updated);
        return updated;
    });

    let passRecord = null;
    if (newPassword) {
        passRecord = { 
            password: newPassword, 
            updatedAt: Date.now(),
            playerId 
        };
        setPasswords(prev => {
            const updated = { ...prev, [playerId]: passRecord };
            storage.save('passwords', updated);
            return updated;
        });
    }

    // 2. Send til skyen
    try {
        const promises = [cloudSave('settings', playerId, { ...newSettings, playerId })];
        if (passRecord) {
            promises.push(cloudSave('password_item', playerId, passRecord));
        }
        await Promise.all(promises);
        triggerToast("Lagret i skyen");
    } catch (e) {
        triggerErrorToast("Lagret lokalt (frakoblet)");
    }
  };

  const handleLogin = (u: User) => {
    setUser(u);
    storage.save('session_user', u);
    if(u.role === 'admin') setView('overview'); 
    else { setSelectedPlayerId(u.id); setView('player'); }
  };

  const handleLogout = () => { 
    setUser(null); 
    storage.remove('session_user');
    setView('login'); 
    setSelectedPlayerId(null); 
  };

  const saveFine = async (fine: FineEntry) => {
    setFines(prev => {
      const newList = prev.find(f => f.id === fine.id) ? prev.map(f => f.id === fine.id ? fine : f) : [...prev, fine];
      storage.save('fines', newList);
      return newList;
    });
    await cloudSave('fine', fine.id, fine);
  };

  const deleteFine = async (id: string) => {
    setFines(prev => {
        const newList = prev.filter(f => f.id !== id);
        storage.save('fines', newList);
        return newList;
    });
    if (selectedFineId === id) { setSelectedFineId(null); setView('list'); }
    await cloudDelete('fine', id);
    triggerToast("Slettet");
  };

  const handleUpdatePlayer = async (playerId: string, updates: Partial<Player>) => {
    setPlayers(prev => {
        const updatedPlayers = prev.map(p => p.id === playerId ? { ...p, ...updates } : p);
        storage.save('players', updatedPlayers);
        const player = updatedPlayers.find(p => p.id === playerId);
        if (player) cloudSave('player', playerId, player);
        return updatedPlayers;
    });
    triggerToast("Spiller oppdatert");
  };

  const handleAddPlayer = async (name: string, position: string) => {
      const newPlayer: Player = { id: crypto.randomUUID(), name, position, systemRole: 'user' };
      setPlayers(prev => {
          const newList = [...prev, newPlayer];
          storage.save('players', newList);
          return newList;
      });
      await cloudSave('player', newPlayer.id, newPlayer);
      triggerToast("Spiller lagt til");
  };

  const handleRemovePlayer = async (id: string) => {
      setPlayers(prev => {
          const newList = prev.filter(p => p.id !== id);
          storage.save('players', newList);
          return newList;
      });
      await cloudDelete('player', id);
      triggerToast("Spiller fjernet");
  };

  const handleToggleAdmin = async (playerId: string) => {
      setPlayers(prev => {
          const updated = prev.map(p => p.id === playerId ? { ...p, systemRole: (p.systemRole === 'admin' ? 'user' : 'admin') as any } : p);
          storage.save('players', updated);
          const player = updated.find(p => p.id === playerId);
          if (player) cloudSave('player', playerId, player);
          return updated;
      });
      triggerToast("Rettigheter endret");
  };

  const handleAddPresetFine = async (label: string, amount: number, icon: string) => {
      const newPreset: PresetFine = { id: crypto.randomUUID(), label, amount, icon };
      setPresetFines(prev => {
          const newList = [...prev, newPreset];
          storage.save('presets', newList);
          return newList;
      });
      await cloudSave('preset', newPreset.id, newPreset);
      triggerToast("Bot lagt til");
  };

  const handleRemovePresetFine = async (id: string) => {
      setPresetFines(prev => {
          const newList = prev.filter(f => f.id !== id);
          storage.save('presets', newList);
          return newList;
      });
      await cloudDelete('preset', id);
      triggerToast("Bot fjernet");
  };

  const handleAddRole = async (name: string, color: string) => {
      const newRole: RoleDefinition = { id: crypto.randomUUID(), name, color };
      setRoles(prev => {
          const newList = [...prev, newRole];
          storage.save('roles', newList);
          return newList;
      });
      await cloudSave('role', newRole.id, newRole);
      triggerToast("Rolle lagt til");
  };

  const handleRemoveRole = async (id: string) => {
      setRoles(prev => {
          const newList = prev.filter(r => r.id !== id);
          storage.save('roles', newList);
          return newList;
      });
      await cloudDelete('role', id);
      triggerToast("Rolle fjernet");
  };

  const pushAllToCloud = async () => {
    setIsSyncing(true);
    try {
      await Promise.all([
        cloudSaveBulk('fine', fines),
        cloudSaveBulk('player', players),
        cloudSaveBulk('preset', presetFines),
        cloudSaveBulk('role', roles)
      ]);
      triggerToast("Alt lagret i skyen!");
    } catch (e) {
      triggerErrorToast("Tilkoblingsfeil.");
    } finally { setIsSyncing(false); }
  };

  const triggerToast = (msg: string) => {
    setShowSuccessToast(msg);
    setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const triggerErrorToast = (msg: string) => {
    setShowErrorToast(msg);
    setTimeout(() => setShowErrorToast(null), 3000);
  };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold tracking-tight">NHHI FC Botkassa våkner...</p>
      </div>
    );
  }

  const currentSelectedFine = fines.find(f => f.id === selectedFineId);
  const currentSelectedPlayer = players.find(p => p.id === (selectedPlayerId || user?.id));

  const getFineDetailPlayer = (fine: FineEntry) => {
      const p = players.find(x => x.id === fine.playerId);
      if (p) return p;
      return { id: fine.playerId, name: 'Slettet spiller', systemRole: 'user' as const };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase">{showSuccessToast}</span>
        </div>
      )}

      {showErrorToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <AlertTriangle size={16} />
          <span className="text-xs font-bold uppercase">{showErrorToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700 transition-colors"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <button onClick={() => syncFromCloud()} className={`p-2 rounded-full ${isSyncing ? 'animate-pulse text-amber-400' : 'text-green-400'}`}>
                                <Cloud size={14} />
                            </button>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView onLogin={handleLogin} passwords={passwords} onSetPassword={handleUpdateSettings} players={players} />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? (
                currentSelectedFine ? (
                    <FineDetailView 
                        fine={currentSelectedFine} 
                        player={getFineDetailPlayer(currentSelectedFine)} 
                        currentUser={user} 
                        presetFines={presetFines} 
                        onBack={() => setView('list')} 
                        onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} 
                        onAddComment={(fid, t) => saveFine({...currentSelectedFine, comments: [...(currentSelectedFine.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]})}
                        onDeleteComment={(fid, cid) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).filter(c => c.id !== cid)})}
                        onToggleFineReaction={(fid, e) => { const r = currentSelectedFine.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...currentSelectedFine, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) }}
                        onToggleCommentReaction={(fid, cid, e) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).map(c => c.id === cid ? {...c, reactions: (c.reactions || []).findIndex(x => x.userId === user.id && x.emoji === e) > -1 ? (c.reactions || []).filter(x => !(x.userId === user.id && x.emoji === e)) : [...(c.reactions || []), {emoji: e, userId: user.id}]} : c)})}
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onAdminPay={(fid) => saveFine({...currentSelectedFine, status: 'paid', payRequest: undefined})} 
                    />
                ) : ( (setView('list'), null) )
            ) :
            view === 'player' ? (
                currentSelectedPlayer ? (
                    <PlayerProfileView 
                        player={currentSelectedPlayer} 
                        currentUserRole={user.role} 
                        currentUserId={user.id}
                        isOwnProfile={user.id === currentSelectedPlayer.id} 
                        fines={fines.filter(f => f.playerId === currentSelectedPlayer.id)} 
                        settings={settings[currentSelectedPlayer.id] || { pushEnabled: false }} 
                        presetFines={presetFines} 
                        roles={roles} 
                        onUpdateSettings={handleUpdateSettings} 
                        onUpdatePlayer={handleUpdatePlayer} 
                        onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} 
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} 
                        onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} 
                        onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} 
                        onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} 
                    />
                ) : ( (setView('overview'), null) )
            ) : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          hasPasswordSet={!!passwords[user.id]}
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={handleUpdateSettings} 
          onPushToCloud={pushAllToCloud}
          isSyncing={isSyncing}
          onCancel={() => setShowSettingsModal(false)} 
          onAddPlayer={handleAddPlayer}
          onRemovePlayer={handleRemovePlayer}
          onToggleAdmin={handleToggleAdmin}
          onAddPresetFine={handleAddPresetFine}
          onRemovePresetFine={handleRemovePresetFine}
          onAddRole={handleAddRole}
          onRemoveRole={handleRemoveRole}
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players, roles, presets: presetFines}} 
        />
      )}
    </div>
  );
};
export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Player, User } from '../types';
import { User as UserIcon, Shield, Search, Lock, ChevronLeft, ArrowRight, Loader2, AlertCircle } from 'lucide-react';
import { Button } from './Button';

interface LoginViewProps {
  onLogin: (user: User) => void;
  passwords: Record<string, any>; // Nå et objekt med {password, updatedAt}
  onSetPassword: (playerId: string, pass: string) => void;
  players: Player[];
}

export const LoginView: React.FC<LoginViewProps> = ({ onLogin, passwords, players }) => {
  const [query, setQuery] = useState('');
  const [selectedPlayer, setSelectedPlayer] = useState<Player | null>(null);
  const [password, setPassword] = useState('');
  const [isVerifying, setIsVerifying] = useState(false);
  const [error, setError] = useState('');
  const passwordInputRef = useRef<HTMLInputElement>(null);

  const DEFAULT_PASSWORD = '1234';

  useEffect(() => {
    if (selectedPlayer && passwordInputRef.current) {
        passwordInputRef.current.focus();
    }
  }, [selectedPlayer]);

  const filteredPlayers = players.filter(p => 
    p.name.toLowerCase().includes(query.toLowerCase())
  );

  const handlePlayerClick = (player: Player) => {
      setSelectedPlayer(player);
      setPassword('');
      setError('');
  };

  const handleSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!selectedPlayer) return;

      setIsVerifying(true);
      setError('');

      // Simuler en liten sjekk for bedre UX
      await new Promise(r => setTimeout(r, 600));

      const passRecord = passwords[selectedPlayer.id];
      const correctPassword = passRecord?.password || DEFAULT_PASSWORD;

      if (password === correctPassword) {
          onLogin({ 
            id: selectedPlayer.id, 
            name: selectedPlayer.name, 
            role: selectedPlayer.systemRole 
          });
      } else {
          setError('Feil passord. Prøv 1234 hvis du er ny.');
          setPassword('');
          if (passwordInputRef.current) passwordInputRef.current.focus();
      }

      setIsVerifying(false);
  };

  if (selectedPlayer) {
      return (
        <div className="flex flex-col items-center justify-center min-h-screen px-4 py-12">
             <div className={`bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm text-center border border-slate-100 animate-in fade-in slide-in-from-right-4 duration-300 relative ${error ? 'animate-shake' : ''}`}>
                <button 
                    onClick={() => setSelectedPlayer(null)}
                    className="absolute top-8 left-8 p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full transition-colors"
                >
                    <ChevronLeft size={24} />
                </button>

                <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600 shadow-sm mt-4">
                     <UserIcon size={32} />
                </div>

                <h2 className="text-xl font-bold text-slate-900 mb-1">{selectedPlayer.name}</h2>
                <p className="text-slate-500 text-sm mb-8">
                    Logg inn med ditt passord
                </p>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="relative">
                        <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                        <input
                            ref={passwordInputRef}
                            type="password"
                            value={password}
                            onChange={(e) => {
                                setPassword(e.target.value);
                                if(error) setError('');
                            }}
                            placeholder="Passord (f.eks 1234)"
                            className={`w-full pl-9 pr-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 outline-none text-slate-900 transition-all ${
                                error 
                                ? 'border-red-300 focus:ring-red-200 bg-red-50/30' 
                                : 'border-slate-200 focus:ring-blue-500'
                            }`}
                        />
                    </div>

                    {error && (
                        <div className="flex items-center justify-center text-xs text-red-600 font-bold animate-in fade-in slide-in-from-top-1">
                            <AlertCircle size={12} className="mr-1" />
                            {error}
                        </div>
                    )}

                    <Button type="submit" fullWidth disabled={isVerifying || !password}>
                        {isVerifying ? (
                            <Loader2 className="animate-spin w-5 h-5" />
                        ) : (
                            <>
                                Logg inn <ArrowRight size={16} className="ml-2" />
                            </>
                        )}
                    </Button>
                </form>
             </div>
        </div>
      );
  }

  return (
    <div className="flex flex-col items-center justify-center min-h-screen px-4 py-12">
      <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm text-center border border-slate-100 animate-in fade-in zoom-in duration-300 relative">

        <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 text-white shadow-lg rotate-3">
          <Shield size={30} />
        </div>

        <h1 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">NHHI FC</h1>
        <p className="text-slate-400 text-xs mb-8 font-bold uppercase tracking-widest">Botkassa</p>

        <div className="relative mb-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
          <input 
            type="text"
            placeholder="Søk navn..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="w-full pl-9 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-slate-900"
          />
        </div>

        <div className="space-y-2 max-h-[40vh] overflow-y-auto pr-2 no-scrollbar">
          {filteredPlayers.map(player => (
            <button
              key={player.id}
              onClick={() => handlePlayerClick(player)}
              className="w-full flex items-center p-3 hover:bg-blue-50 border border-slate-100 rounded-2xl transition-all group active:scale-95"
            >
              <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">
                <UserIcon size={16} />
              </div>
              <div className="text-left">
                <div className="font-bold text-slate-800 text-sm">{player.name}</div>
                <div className="text-[10px] text-slate-400 uppercase font-black tracking-widest">
                  {player.customRole || player.position || 'Spiller'}
                </div>
              </div>
            </button>
          ))}
          {filteredPlayers.length === 0 && (
            <p className="text-slate-400 text-xs py-4 italic">Ingen spillere funnet</p>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ViewState, FineEntry, User, TimeFilter, UserSettings, Player, PresetFine, RoleDefinition } from './types';
import { DEFAULT_PLAYERS, PRESET_FINES as DEFAULT_PRESET_FINES, DEFAULT_ROLES } from './constants';
import { AddFineView } from './components/AddFineView';
import { StatsView } from './components/StatsView';
import { PlayerProfileView } from './components/PlayerProfileView';
import { LoginView } from './components/LoginView';
import { FineListView } from './components/FineListView';
import { NotificationsView } from './components/NotificationsView';
import { SettingsModal } from './components/SettingsModal';
import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { storage } from './services/storageService';
import { cloudSave, cloudDelete, cloudFetchAll, subscribeToCloudChanges, cloudSaveBulk } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);
  const [showErrorToast, setShowErrorToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [presetFines, setPresetFines] = useState<PresetFine[]>([]);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>([]);

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  const lastLocalSaveRef = useRef<number>(0);

  useEffect(() => {
    const loadedUser = storage.get<User | null>('session_user', null);
    const loadedFines = storage.get<FineEntry[]>('fines', []);
    const loadedPresets = storage.get<PresetFine[]>('presets', DEFAULT_PRESET_FINES);
    const loadedRoles = storage.get<RoleDefinition[]>('roles', DEFAULT_ROLES);
    const loadedSettings = storage.get<Record<string, UserSettings>>('settings', {});

    const storedPlayers = storage.get<Player[]>('players', []);
    const playerMap = new Map<string, Player>();
    DEFAULT_PLAYERS.forEach(p => playerMap.set(p.id, p));
    storedPlayers.forEach(p => playerMap.set(p.id, p));

    setFines(loadedFines);
    setPlayers(Array.from(playerMap.values()));
    setPresetFines(loadedPresets);
    setRoles(loadedRoles);
    setSettings(loadedSettings);

    if (loadedUser) {
      setUser(loadedUser);
      if (loadedUser.role === 'admin') setView('overview');
      else { setSelectedPlayerId(loadedUser.id); setView('player'); }
    }

    syncFromCloud();

    const subscription = subscribeToCloudChanges(() => {
      syncFromCloud(true); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const syncFromCloud = async (silent = false) => {
    if (Date.now() - lastLocalSaveRef.current < 5000 && silent) return;

    if (!silent) setIsSyncing(true);

    try {
      const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings] = (await Promise.all([
        cloudFetchAll('fine'),
        cloudFetchAll('player'),
        cloudFetchAll('preset'),
        cloudFetchAll('role'),
        cloudFetchAll('settings')
      ])) as [FineEntry[], Player[], PresetFine[], RoleDefinition[], any[]];

      if (cloudPlayers && cloudPlayers.length > 0) {
          setPlayers(prevLocal => {
            const mergedMap = new Map<string, Player>();
            DEFAULT_PLAYERS.forEach(p => mergedMap.set(p.id, p));
            prevLocal.forEach(p => mergedMap.set(p.id, p));
            cloudPlayers.forEach(cp => mergedMap.set(cp.id, cp));
            const final = Array.from(mergedMap.values());
            storage.save('players', final);
            return final;
          });
      }

      setFines(prevLocal => {
        const now = Date.now();
        const cloudMap = new Map(cloudFines.map(f => [f.id, f]));
        const merged = prevLocal.filter(lf => cloudMap.has(lf.id) || (now - lf.timestamp) < 60000);
        cloudFines.forEach(cf => { if (!merged.find(m => m.id === cf.id)) merged.push(cf); });
        storage.save('fines', merged);
        return [...merged];
      });

      if (cloudPresets.length > 0) { setPresetFines(cloudPresets); storage.save('presets', cloudPresets); }
      if (cloudRoles.length > 0) { setRoles(cloudRoles); storage.save('roles', cloudRoles); }

      const settingsMap: Record<string, UserSettings> = {};
      cloudSettings.forEach((s: any) => settingsMap[s.playerId] = s);
      setSettings(settingsMap);

      if (!silent) triggerToast("Synkronisert");
    } catch (error) {
      console.error("Sync error:", error);
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings) => {
    lastLocalSaveRef.current = Date.now();

    setSettings(prev => {
        const updated = { ...prev, [playerId]: newSettings };
        storage.save('settings', updated);
        return updated;
    });

    try {
        await cloudSave('settings', playerId, { ...newSettings, playerId });
        triggerToast("Lagret i skyen");
    } catch (e) {
        triggerErrorToast("Lagret lokalt (frakoblet)");
    }
  };

  const handleLogin = (u: User) => {
    setUser(u);
    storage.save('session_user', u);
    if(u.role === 'admin') setView('overview'); 
    else { setSelectedPlayerId(u.id); setView('player'); }
  };

  const handleLogout = () => { 
    setUser(null); 
    storage.remove('session_user');
    setView('login'); 
    setSelectedPlayerId(null); 
  };

  const saveFine = async (fine: FineEntry) => {
    setFines(prev => {
      const newList = prev.find(f => f.id === fine.id) ? prev.map(f => f.id === fine.id ? fine : f) : [...prev, fine];
      storage.save('fines', newList);
      return newList;
    });
    await cloudSave('fine', fine.id, fine);
  };

  const deleteFine = async (id: string) => {
    setFines(prev => {
        const newList = prev.filter(f => f.id !== id);
        storage.save('fines', newList);
        return newList;
    });
    if (selectedFineId === id) { setSelectedFineId(null); setView('list'); }
    await cloudDelete('fine', id);
    triggerToast("Slettet");
  };

  const handleUpdatePlayer = async (playerId: string, updates: Partial<Player>) => {
    setPlayers(prev => {
        const updatedPlayers = prev.map(p => p.id === playerId ? { ...p, ...updates } : p);
        storage.save('players', updatedPlayers);
        const player = updatedPlayers.find(p => p.id === playerId);
        if (player) cloudSave('player', playerId, player);
        return updatedPlayers;
    });
    triggerToast("Spiller oppdatert");
  };

  const handleAddPlayer = async (name: string, position: string) => {
      const newPlayer: Player = { id: crypto.randomUUID(), name, position, systemRole: 'user' };
      setPlayers(prev => {
          const newList = [...prev, newPlayer];
          storage.save('players', newList);
          return newList;
      });
      await cloudSave('player', newPlayer.id, newPlayer);
      triggerToast("Spiller lagt til");
  };

  const handleRemovePlayer = async (id: string) => {
      setPlayers(prev => {
          const newList = prev.filter(p => p.id !== id);
          storage.save('players', newList);
          return newList;
      });
      await cloudDelete('player', id);
      triggerToast("Spiller fjernet");
  };

  const handleToggleAdmin = async (playerId: string) => {
      setPlayers(prev => {
          const updated = prev.map(p => p.id === playerId ? { ...p, systemRole: (p.systemRole === 'admin' ? 'user' : 'admin') as any } : p);
          storage.save('players', updated);
          const player = updated.find(p => p.id === playerId);
          if (player) cloudSave('player', playerId, player);
          return updated;
      });
      triggerToast("Rettigheter endret");
  };

  const handleAddPresetFine = async (label: string, amount: number, icon: string) => {
      const newPreset: PresetFine = { id: crypto.randomUUID(), label, amount, icon };
      setPresetFines(prev => {
          const newList = [...prev, newPreset];
          storage.save('presets', newList);
          return newList;
      });
      await cloudSave('preset', newPreset.id, newPreset);
      triggerToast("Bot lagt til");
  };

  const handleRemovePresetFine = async (id: string) => {
      setPresetFines(prev => {
          const newList = prev.filter(f => f.id !== id);
          storage.save('presets', newList);
          return newList;
      });
      await cloudDelete('preset', id);
      triggerToast("Bot fjernet");
  };

  const handleAddRole = async (name: string, color: string) => {
      const newRole: RoleDefinition = { id: crypto.randomUUID(), name, color };
      setRoles(prev => {
          const newList = [...prev, newRole];
          storage.save('roles', newList);
          return newList;
      });
      await cloudSave('role', newRole.id, newRole);
      triggerToast("Rolle lagt til");
  };

  const handleRemoveRole = async (id: string) => {
      setRoles(prev => {
          const newList = prev.filter(r => r.id !== id);
          storage.save('roles', newList);
          return newList;
      });
      await cloudDelete('role', id);
      triggerToast("Rolle fjernet");
  };

  const pushAllToCloud = async () => {
    setIsSyncing(true);
    try {
      await Promise.all([
        cloudSaveBulk('fine', fines),
        cloudSaveBulk('player', players),
        cloudSaveBulk('preset', presetFines),
        cloudSaveBulk('role', roles)
      ]);
      triggerToast("Alt lagret i skyen!");
    } catch (e) {
      triggerErrorToast("Tilkoblingsfeil.");
    } finally { setIsSyncing(false); }
  };

  const triggerToast = (msg: string) => {
    setShowSuccessToast(msg);
    setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const triggerErrorToast = (msg: string) => {
    setShowErrorToast(msg);
    setTimeout(() => setShowErrorToast(null), 3000);
  };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold tracking-tight">NHHI FC Botkassa våkner...</p>
      </div>
    );
  }

  const currentSelectedFine = fines.find(f => f.id === selectedFineId);
  const currentSelectedPlayer = players.find(p => p.id === (selectedPlayerId || user?.id));

  const getFineDetailPlayer = (fine: FineEntry) => {
      const p = players.find(x => x.id === fine.playerId);
      if (p) return p;
      return { id: fine.playerId, name: 'Slettet spiller', systemRole: 'user' as const };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase">{showSuccessToast}</span>
        </div>
      )}

      {showErrorToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <AlertTriangle size={16} />
          <span className="text-xs font-bold uppercase">{showErrorToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700 transition-colors"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <button onClick={() => syncFromCloud()} className={`p-2 rounded-full ${isSyncing ? 'animate-pulse text-amber-400' : 'text-green-400'}`}>
                                <Cloud size={14} />
                            </button>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView onLogin={handleLogin} players={players} />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? (
                currentSelectedFine ? (
                    <FineDetailView 
                        fine={currentSelectedFine} 
                        player={getFineDetailPlayer(currentSelectedFine)} 
                        currentUser={user} 
                        presetFines={presetFines} 
                        onBack={() => setView('list')} 
                        onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} 
                        onAddComment={(fid, t) => saveFine({...currentSelectedFine, comments: [...(currentSelectedFine.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]})}
                        onDeleteComment={(fid, cid) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).filter(c => c.id !== cid)})}
                        onToggleFineReaction={(fid, e) => { const r = currentSelectedFine.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...currentSelectedFine, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) }}
                        onToggleCommentReaction={(fid, cid, e) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).map(c => c.id === cid ? {...c, reactions: (c.reactions || []).findIndex(x => x.userId === user.id && x.emoji === e) > -1 ? (c.reactions || []).filter(x => !(x.userId === user.id && x.emoji === e)) : [...(c.reactions || []), {emoji: e, userId: user.id}]} : c)})}
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onAdminPay={(fid) => saveFine({...currentSelectedFine, status: 'paid', payRequest: undefined})} 
                    />
                ) : ( (setView('list'), null) )
            ) :
            view === 'player' ? (
                currentSelectedPlayer ? (
                    <PlayerProfileView 
                        player={currentSelectedPlayer} 
                        currentUserRole={user.role} 
                        currentUserId={user.id}
                        isOwnProfile={user.id === currentSelectedPlayer.id} 
                        fines={fines.filter(f => f.playerId === currentSelectedPlayer.id)} 
                        settings={settings[currentSelectedPlayer.id] || { pushEnabled: false }} 
                        presetFines={presetFines} 
                        roles={roles} 
                        onUpdateSettings={handleUpdateSettings} 
                        onUpdatePlayer={handleUpdatePlayer} 
                        onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} 
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} 
                        onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} 
                        onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} 
                        onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} 
                    />
                ) : ( (setView('overview'), null) )
            ) : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={handleUpdateSettings} 
          onPushToCloud={pushAllToCloud}
          isSyncing={isSyncing}
          onCancel={() => setShowSettingsModal(false)} 
          onAddPlayer={handleAddPlayer}
          onRemovePlayer={handleRemovePlayer}
          onToggleAdmin={handleToggleAdmin}
          onAddPresetFine={handleAddPresetFine}
          onRemovePresetFine={handleRemovePresetFine}
          onAddRole={handleAddRole}
          onRemoveRole={handleRemoveRole}
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players, roles, presets: presetFines}} 
        />
      )}
    </div>
  );
};
export default App;

