import React, { useState, useEffect, useMemo, useRef } from 'react';
import { ViewState, FineEntry, User, TimeFilter, UserSettings, Player, PresetFine, RoleDefinition } from './types';
import { DEFAULT_PLAYERS, PRESET_FINES as DEFAULT_PRESET_FINES, DEFAULT_ROLES } from './constants';
import { AddFineView } from './components/AddFineView';
import { StatsView } from './components/StatsView';
import { PlayerProfileView } from './components/PlayerProfileView';
import { LoginView } from './components/LoginView';
import { FineListView } from './components/FineListView';
import { NotificationsView } from './components/NotificationsView';
import { SettingsModal } from './components/SettingsModal';
import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { storage } from './services/storageService';
import { cloudSave, cloudDelete, cloudFetchAll, subscribeToCloudChanges, cloudSaveBulk } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud, AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);
  const [showErrorToast, setShowErrorToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>([]);
  const [presetFines, setPresetFines] = useState<PresetFine[]>([]);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>([]);

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  const lastLocalSaveRef = useRef<number>(0);

  useEffect(() => {
    // Last lokal data først
    const loadedUser = storage.get<User | null>('session_user', null);
    const loadedFines = storage.get<FineEntry[]>('fines', []);
    const loadedPresets = storage.get<PresetFine[]>('presets', DEFAULT_PRESET_FINES);
    const loadedRoles = storage.get<RoleDefinition[]>('roles', DEFAULT_ROLES);
    const loadedSettings = storage.get<Record<string, UserSettings>>('settings', {});

    const storedPlayers = storage.get<Player[]>('players', []);
    const playerMap = new Map<string, Player>();
    DEFAULT_PLAYERS.forEach(p => playerMap.set(p.id, p));
    storedPlayers.forEach(p => playerMap.set(p.id, p));

    setFines(loadedFines);
    setPlayers(Array.from(playerMap.values()));
    setPresetFines(loadedPresets);
    setRoles(loadedRoles);
    setSettings(loadedSettings);

    if (loadedUser) {
      setUser(loadedUser);
      if (loadedUser.role === 'admin') setView('overview');
      else { setSelectedPlayerId(loadedUser.id); setView('player'); }
    }

    // Start sky-synk
    syncFromCloud();

    const subscription = subscribeToCloudChanges(() => {
      syncFromCloud(true); 
    });

    return () => {
      subscription.unsubscribe();
    };
  }, []);

  const syncFromCloud = async (silent = false) => {
    // Hindre overskriving hvis vi nettopp har lagret noe lokalt
    if (Date.now() - lastLocalSaveRef.current < 5000 && silent) return;

    if (!silent) setIsSyncing(true);

    try {
      const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings] = (await Promise.all([
        cloudFetchAll('fine'),
        cloudFetchAll('player'),
        cloudFetchAll('preset'),
        cloudFetchAll('role'),
        cloudFetchAll('settings')
      ])) as [FineEntry[], Player[], PresetFine[], RoleDefinition[], any[]];

      // Robust spiller-sync
      if (cloudPlayers && cloudPlayers.length > 0) {
          setPlayers(prevLocal => {
            const mergedMap = new Map<string, Player>();
            DEFAULT_PLAYERS.forEach(p => mergedMap.set(p.id, p));
            prevLocal.forEach(p => mergedMap.set(p.id, p));
            cloudPlayers.forEach(cp => mergedMap.set(cp.id, cp));
            const final = Array.from(mergedMap.values());
            storage.save('players', final);
            return final;
          });
      }

      // Bøter
      setFines(prevLocal => {
        const now = Date.now();
        const cloudMap = new Map(cloudFines.map(f => [f.id, f]));
        const merged = prevLocal.filter(lf => cloudMap.has(lf.id) || (now - lf.timestamp) < 60000);
        cloudFines.forEach(cf => { if (!merged.find(m => m.id === cf.id)) merged.push(cf); });
        storage.save('fines', merged);
        return [...merged];
      });

      if (cloudPresets.length > 0) { setPresetFines(cloudPresets); storage.save('presets', cloudPresets); }
      if (cloudRoles.length > 0) { setRoles(cloudRoles); storage.save('roles', cloudRoles); }

      const settingsMap: Record<string, UserSettings> = {};
      cloudSettings.forEach((s: any) => settingsMap[s.playerId] = s);
      setSettings(settingsMap);

      if (!silent) triggerToast("Synkronisert");
    } catch (error) {
      console.error("Sync error:", error);
    } finally {
      setIsSyncing(false);
      setIsLoading(false);
    }
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings) => {
    lastLocalSaveRef.current = Date.now();

    setSettings(prev => {
        const updated = { ...prev, [playerId]: newSettings };
        storage.save('settings', updated);
        return updated;
    });

    try {
        await cloudSave('settings', playerId, { ...newSettings, playerId });
        triggerToast("Lagret i skyen");
    } catch (e) {
        triggerErrorToast("Lagret lokalt (frakoblet)");
    }
  };

  const handleLogin = (u: User) => {
    setUser(u);
    storage.save('session_user', u);
    if(u.role === 'admin') setView('overview'); 
    else { setSelectedPlayerId(u.id); setView('player'); }
  };

  const handleLogout = () => { 
    setUser(null); 
    storage.remove('session_user');
    setView('login'); 
    setSelectedPlayerId(null); 
  };

  const saveFine = async (fine: FineEntry) => {
    setFines(prev => {
      const newList = prev.find(f => f.id === fine.id) ? prev.map(f => f.id === fine.id ? fine : f) : [...prev, fine];
      storage.save('fines', newList);
      return newList;
    });
    await cloudSave('fine', fine.id, fine);
  };

  const deleteFine = async (id: string) => {
    setFines(prev => {
        const newList = prev.filter(f => f.id !== id);
        storage.save('fines', newList);
        return newList;
    });
    if (selectedFineId === id) { setSelectedFineId(null); setView('list'); }
    await cloudDelete('fine', id);
    triggerToast("Slettet");
  };

  const handleUpdatePlayer = async (playerId: string, updates: Partial<Player>) => {
    setPlayers(prev => {
        const updatedPlayers = prev.map(p => p.id === playerId ? { ...p, ...updates } : p);
        storage.save('players', updatedPlayers);
        const player = updatedPlayers.find(p => p.id === playerId);
        if (player) cloudSave('player', playerId, player);
        return updatedPlayers;
    });
    triggerToast("Spiller oppdatert");
  };

  const handleAddPlayer = async (name: string, position: string) => {
      const newPlayer: Player = { id: crypto.randomUUID(), name, position, systemRole: 'user' };
      setPlayers(prev => {
          const newList = [...prev, newPlayer];
          storage.save('players', newList);
          return newList;
      });
      await cloudSave('player', newPlayer.id, newPlayer);
      triggerToast("Spiller lagt til");
  };

  const handleRemovePlayer = async (id: string) => {
      setPlayers(prev => {
          const newList = prev.filter(p => p.id !== id);
          storage.save('players', newList);
          return newList;
      });
      await cloudDelete('player', id);
      triggerToast("Spiller fjernet");
  };

  const handleToggleAdmin = async (playerId: string) => {
      setPlayers(prev => {
          const updated = prev.map(p => p.id === playerId ? { ...p, systemRole: (p.systemRole === 'admin' ? 'user' : 'admin') as any } : p);
          storage.save('players', updated);
          const player = updated.find(p => p.id === playerId);
          if (player) cloudSave('player', playerId, player);
          return updated;
      });
      triggerToast("Rettigheter endret");
  };

  const handleAddPresetFine = async (label: string, amount: number, icon: string) => {
      const newPreset: PresetFine = { id: crypto.randomUUID(), label, amount, icon };
      setPresetFines(prev => {
          const newList = [...prev, newPreset];
          storage.save('presets', newList);
          return newList;
      });
      await cloudSave('preset', newPreset.id, newPreset);
      triggerToast("Bot lagt til");
  };

  const handleRemovePresetFine = async (id: string) => {
      setPresetFines(prev => {
          const newList = prev.filter(f => f.id !== id);
          storage.save('presets', newList);
          return newList;
      });
      await cloudDelete('preset', id);
      triggerToast("Bot fjernet");
  };

  const handleAddRole = async (name: string, color: string) => {
      const newRole: RoleDefinition = { id: crypto.randomUUID(), name, color };
      setRoles(prev => {
          const newList = [...prev, newRole];
          storage.save('roles', newList);
          return newList;
      });
      await cloudSave('role', newRole.id, newRole);
      triggerToast("Rolle lagt til");
  };

  const handleRemoveRole = async (id: string) => {
      setRoles(prev => {
          const newList = prev.filter(r => r.id !== id);
          storage.save('roles', newList);
          return newList;
      });
      await cloudDelete('role', id);
      triggerToast("Rolle fjernet");
  };

  const pushAllToCloud = async () => {
    setIsSyncing(true);
    try {
      await Promise.all([
        cloudSaveBulk('fine', fines),
        cloudSaveBulk('player', players),
        cloudSaveBulk('preset', presetFines),
        cloudSaveBulk('role', roles)
      ]);
      triggerToast("Alt lagret i skyen!");
    } catch (e) {
      triggerErrorToast("Tilkoblingsfeil.");
    } finally { setIsSyncing(false); }
  };

  const triggerToast = (msg: string) => {
    setShowSuccessToast(msg);
    setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const triggerErrorToast = (msg: string) => {
    setShowErrorToast(msg);
    setTimeout(() => setShowErrorToast(null), 3000);
  };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold tracking-tight">NHHI FC Botkassa våkner...</p>
      </div>
    );
  }

  const currentSelectedFine = fines.find(f => f.id === selectedFineId);
  const currentSelectedPlayer = players.find(p => p.id === (selectedPlayerId || user?.id));

  const getFineDetailPlayer = (fine: FineEntry) => {
      const p = players.find(x => x.id === fine.playerId);
      if (p) return p;
      return { id: fine.playerId, name: 'Slettet spiller', systemRole: 'user' as const };
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase">{showSuccessToast}</span>
        </div>
      )}

      {showErrorToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <AlertTriangle size={16} />
          <span className="text-xs font-bold uppercase">{showErrorToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700 transition-colors"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <button onClick={() => syncFromCloud()} className={`p-2 rounded-full ${isSyncing ? 'animate-pulse text-amber-400' : 'text-green-400'}`}>
                                <Cloud size={14} />
                            </button>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700 transition-colors"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView onLogin={handleLogin} players={players} />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? (
                currentSelectedFine ? (
                    <FineDetailView 
                        fine={currentSelectedFine} 
                        player={getFineDetailPlayer(currentSelectedFine)} 
                        currentUser={user} 
                        presetFines={presetFines} 
                        onBack={() => setView('list')} 
                        onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} 
                        onAddComment={(fid, t) => saveFine({...currentSelectedFine, comments: [...(currentSelectedFine.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]})}
                        onDeleteComment={(fid, cid) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).filter(c => c.id !== cid)})}
                        onToggleFineReaction={(fid, e) => { const r = currentSelectedFine.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...currentSelectedFine, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) }}
                        onToggleCommentReaction={(fid, cid, e) => saveFine({...currentSelectedFine, comments: (currentSelectedFine.comments || []).map(c => c.id === cid ? {...c, reactions: (c.reactions || []).findIndex(x => x.userId === user.id && x.emoji === e) > -1 ? (c.reactions || []).filter(x => !(x.userId === user.id && x.emoji === e)) : [...(c.reactions || []), {emoji: e, userId: user.id}]} : c)})}
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onAdminPay={(fid) => saveFine({...currentSelectedFine, status: 'paid', payRequest: undefined})} 
                    />
                ) : ( (setView('list'), null) )
            ) :
            view === 'player' ? (
                currentSelectedPlayer ? (
                    <PlayerProfileView 
                        player={currentSelectedPlayer} 
                        currentUserRole={user.role} 
                        currentUserId={user.id}
                        isOwnProfile={user.id === currentSelectedPlayer.id} 
                        fines={fines.filter(f => f.playerId === currentSelectedPlayer.id)} 
                        settings={settings[currentSelectedPlayer.id] || { pushEnabled: false }} 
                        presetFines={presetFines} 
                        roles={roles} 
                        onUpdateSettings={handleUpdateSettings} 
                        onUpdatePlayer={handleUpdatePlayer} 
                        onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} 
                        onUpdateFine={saveFine} 
                        onDeleteFine={deleteFine} 
                        onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} 
                        onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} 
                        onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} 
                        onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} 
                    />
                ) : ( (setView('overview'), null) )
            ) : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={handleUpdateSettings} 
          onPushToCloud={pushAllToCloud}
          isSyncing={isSyncing}
          onCancel={() => setShowSettingsModal(false)} 
          onAddPlayer={handleAddPlayer}
          onRemovePlayer={handleRemovePlayer}
          onToggleAdmin={handleToggleAdmin}
          onAddPresetFine={handleAddPresetFine}
          onRemovePresetFine={handleRemovePresetFine}
          onAddRole={handleAddRole}
          onRemoveRole={handleRemoveRole}
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players, roles, presets: presetFines}} 
        />
      )}
    </div>
  );
};
export default App;

import React, { useState } from 'react';
import { Player, User } from '../types';
import { User as UserIcon, Shield, Search, ChevronRight } from 'lucide-react';

interface LoginViewProps {
  onLogin: (user: User) => void;
  players: Player[];
}

export const LoginView: React.FC<LoginViewProps> = ({ onLogin, players }) => {
  const [query, setQuery] = useState('');

  const filteredPlayers = players.filter(p => 
    p.name.toLowerCase().includes(query.toLowerCase())
  );

  const handlePlayerClick = (player: Player) => {
      onLogin({ 
        id: player.id, 
        name: player.name, 
        role: player.systemRole 
      });
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen px-4 py-12">
      <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm text-center border border-slate-100 animate-in fade-in zoom-in duration-300 relative">

        <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 text-white shadow-lg rotate-3">
          <Shield size={30} />
        </div>

        <h1 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">NHHI FC</h1>
        <p className="text-slate-400 text-xs mb-8 font-bold uppercase tracking-widest">Botkassa</p>

        <div className="relative mb-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
          <input 
            type="text"
            placeholder="Søk navn..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="w-full pl-9 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-slate-900"
          />
        </div>

        <div className="space-y-2 max-h-[45vh] overflow-y-auto pr-2 no-scrollbar">
          {filteredPlayers.map(player => (
            <button
              key={player.id}
              onClick={() => handlePlayerClick(player)}
              className="w-full flex items-center justify-between p-3 hover:bg-blue-50 border border-slate-100 rounded-2xl transition-all group active:scale-95"
            >
              <div className="flex items-center">
                <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">
                  <UserIcon size={16} />
                </div>
                <div className="text-left">
                  <div className="font-bold text-slate-800 text-sm">{player.name}</div>
                  <div className="text-[10px] text-slate-400 uppercase font-black tracking-widest">
                    {player.customRole || player.position || 'Spiller'}
                  </div>
                </div>
              </div>
              <ChevronRight size={16} className="text-slate-300 group-hover:text-blue-600" />
            </button>
          ))}
          {filteredPlayers.length === 0 && (
            <p className="text-slate-400 text-xs py-4 italic">Ingen spillere funnet</p>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';
import { UserSettings, User, Player, PresetFine, RoleDefinition } from '../types';
import { X, Smartphone, Save, UploadCloud, RefreshCw, Plus, Trash2, ShieldCheck } from 'lucide-react';
import { ROLE_COLOR_MAP } from '../constants';

interface SettingsModalProps {
  currentUser?: User;
  settings: UserSettings;
  players?: Player[]; 
  presetFines?: PresetFine[];
  roles?: RoleDefinition[]; 
  onSave: (settings: UserSettings) => void;
  onPushToCloud: () => void;
  isSyncing: boolean;
  onCancel: () => void;
  onAddPlayer?: (name: string, position: string) => void;
  onRemovePlayer?: (id: string) => void;
  onToggleAdmin?: (playerId: string) => void;
  onAddPresetFine?: (label: string, amount: number, icon: string) => void;
  onRemovePresetFine?: (id: string) => void;
  onAddRole?: (name: string, color: string) => void; 
  onRemoveRole?: (id: string) => void; 
  onImportData: (data: any) => void;
  exportData: any;
}

const EMOJI_GRID = ['⚽', '🍺', '🍻', '🥃', '⏰', '🏃', '🚀', '🤡', '👔', '📵', '🦵', '📉', '👻', '💰', '🚿', '🏆', '🟥', '🟨'];
const COLORS = Object.keys(ROLE_COLOR_MAP);

export const SettingsModal: React.FC<SettingsModalProps> = ({ 
  currentUser, 
  settings, 
  players = [],
  presetFines = [],
  roles = [],
  onSave, 
  onPushToCloud,
  isSyncing,
  onCancel, 
  onAddPlayer,
  onRemovePlayer,
  onToggleAdmin,
  onAddPresetFine,
  onRemovePresetFine,
  onAddRole,
  onRemoveRole
}) => {
  const [phoneNumber, setPhoneNumber] = useState(settings.phoneNumber || '');
  const [email, setEmail] = useState(settings.email || '');

  const [activeTab, setActiveTab] = useState<'profile' | 'players' | 'fines' | 'roles'>('profile');
  const [newPlayerName, setNewPlayerName] = useState('');
  const [newFineName, setNewFineName] = useState('');
  const [newFineAmount, setNewFineAmount] = useState<number>(30);
  const [newFineIcon, setNewFineIcon] = useState('⚽');
  const [newRoleName, setNewRoleName] = useState('');
  const [newRoleColor, setNewRoleColor] = useState('blue');

  const isSuperAdmin = currentUser?.name === 'Birk Haugnes';

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({ ...settings, phoneNumber, email });
  };

  const renderProfile = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
        <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-4">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Brukerprofil</h4>
                <div className="space-y-4">
                    <div className="space-y-2">
                        <label className="block text-sm font-medium text-slate-700">Telefonnummer</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none"><Smartphone className="h-4 w-4 text-gray-400" /></div>
                            <input type="tel" value={phoneNumber} onChange={(e) => setPhoneNumber(e.target.value)} placeholder="912 34 567" className="block w-full pl-9 py-2.5 text-sm border border-slate-300 rounded-xl bg-white" />
                        </div>
                    </div>
                </div>
            </div>
            <Button type="submit" fullWidth><Save size={18} className="mr-2" />Lagre Profil</Button>
        </form>

        {currentUser?.role === 'admin' && (
            <div className="pt-6 border-t border-slate-100">
                <h4 className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center mb-3">
                    <UploadCloud size={12} className="mr-1" /> Sky-kontroll
                </h4>
                <button 
                    onClick={onPushToCloud}
                    disabled={isSyncing}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white py-2.5 rounded-xl text-xs font-bold hover:bg-blue-700 transition-colors shadow-md disabled:opacity-50"
                >
                    {isSyncing ? <RefreshCw size={14} className="animate-spin" /> : <UploadCloud size={14} />}
                    PUSH LOKAL DATA TIL SKYEN
                </button>
            </div>
        )}
    </div>
  );

  const renderPlayers = () => {
    const sortedPlayers = [...players].sort((a,b) => a.name.localeCompare(b.name));

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
            <div className="space-y-3">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Legg til spiller</h4>
                <div className="flex gap-2">
                    <input 
                        type="text" 
                        value={newPlayerName} 
                        onChange={(e) => setNewPlayerName(e.target.value)} 
                        placeholder="Fullt navn..." 
                        className="flex-1 p-2.5 text-sm border border-slate-300 rounded-xl bg-white shadow-sm" 
                    />
                    <button 
                        onClick={() => { if(newPlayerName.trim() && onAddPlayer) { onAddPlayer(newPlayerName, 'Spiller'); setNewPlayerName(''); } }}
                        className="bg-blue-600 text-white p-2.5 rounded-xl hover:bg-blue-700 shadow-sm shrink-0"
                    >
                        <Plus size={20} />
                    </button>
                </div>
            </div>

            <div className="space-y-2 max-h-[40vh] overflow-y-auto pr-1 no-scrollbar">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Alle spillere ({players.length})</h4>
                {sortedPlayers.map(p => {
                    const isBirk = p.name === 'Birk Haugnes';
                    return (
                        <div key={p.id} className="flex items-center justify-between p-3 bg-white border border-slate-100 rounded-xl hover:shadow-sm transition-all group">
                            <div className="flex items-center gap-3 overflow-hidden">
                                <div className={`w-8 h-8 rounded-full shrink-0 flex items-center justify-center text-xs font-bold ${p.systemRole === 'admin' ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-500'}`}>
                                    {p.name.charAt(0)}
                                </div>
                                <div className="truncate">
                                    <div className="text-xs font-bold text-slate-900 truncate">{p.name}</div>
                                    <div className="text-[10px] text-slate-400 uppercase font-black">{p.systemRole === 'admin' ? 'Botsjef' : 'Spiller'}</div>
                                </div>
                            </div>
                            <div className="flex items-center gap-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity shrink-0 ml-2">
                                {isSuperAdmin && !isBirk && (
                                    <button 
                                        onClick={() => onToggleAdmin && onToggleAdmin(p.id)}
                                        className={`p-2 rounded-lg transition-colors ${p.systemRole === 'admin' ? 'text-amber-500 hover:bg-amber-50' : 'text-slate-300 hover:bg-slate-50'}`}
                                        title="Veksle Botsjef-rettigheter"
                                    >
                                        <ShieldCheck size={18} />
                                    </button>
                                )}
                                {(!isBirk || (isSuperAdmin && isBirk)) && (
                                    <button 
                                        onClick={() => { if(confirm(`Slette ${p.name}?`)) onRemovePlayer && onRemovePlayer(p.id); }}
                                        className="p-2 text-red-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
  };

  const renderFines = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-200 space-y-4 shadow-inner">
            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Ny bot-kategori</h4>
            <div className="space-y-4">
                <div className="space-y-3">
                    <div className="space-y-1">
                        <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Kategori-navn</label>
                        <input type="text" value={newFineName} onChange={(e) => setNewFineName(e.target.value)} placeholder="F.eks: Luke" className="w-full p-2.5 text-sm border border-slate-300 rounded-xl bg-white shadow-sm" />
                    </div>
                    <div className="space-y-1">
                        <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Beløp (kr)</label>
                        <div className="relative">
                            <input type="number" value={newFineAmount} onChange={(e) => setNewFineAmount(Number(e.target.value))} placeholder="Beløp" className="w-full p-2.5 pr-8 text-sm border border-slate-300 rounded-xl bg-white shadow-sm" />
                            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-[10px] font-black text-slate-300">KR</span>
                        </div>
                    </div>
                </div>
                <div>
                    <p className="text-[10px] font-bold text-slate-400 mb-2 uppercase ml-1">Velg ikon</p>
                    <div className="grid grid-cols-6 gap-1.5 max-h-32 overflow-y-auto p-2 bg-white rounded-xl border border-slate-200 no-scrollbar">
                        {EMOJI_GRID.map(e => (
                            <button key={e} onClick={() => setNewFineIcon(e)} className={`w-8 h-8 flex items-center justify-center rounded-lg text-lg transition-all ${newFineIcon === e ? 'bg-blue-100 scale-110 shadow-sm ring-1 ring-blue-300' : 'hover:bg-slate-50'}`}>{e}</button>
                        ))}
                    </div>
                </div>
                <Button fullWidth onClick={() => { if(newFineName && onAddPresetFine) { onAddPresetFine(newFineName, newFineAmount, newFineIcon); setNewFineName(''); } }}>
                    <Plus size={16} className="mr-2" /> Legg til kategori
                </Button>
            </div>
        </div>

        <div className="space-y-2 max-h-[40vh] overflow-y-auto pr-1 no-scrollbar">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Eksisterende kategorier</h4>
            {presetFines.map(f => (
                <div key={f.id} className="flex items-center justify-between p-3 bg-white border border-slate-100 rounded-xl hover:shadow-sm transition-shadow">
                    <div className="flex items-center gap-4 overflow-hidden w-full">
                        <div className="text-2xl shrink-0 w-12 h-12 bg-slate-50 flex items-center justify-center rounded-2xl border border-slate-100">{f.icon}</div>
                        <div className="truncate flex-1">
                            <div className="text-xs font-bold text-slate-900 truncate block w-full">{f.label}</div>
                            <div className="text-[10px] text-blue-600 font-black bg-blue-50 px-2 py-0.5 rounded-full inline-block mt-1 border border-blue-100">{f.amount} kr</div>
                        </div>
                        <button onClick={() => onRemovePresetFine && onRemovePresetFine(f.id)} className="p-2 text-slate-300 hover:text-red-500 rounded-lg transition-colors shrink-0 ml-2"><Trash2 size={18} /></button>
                    </div>
                </div>
            ))}
        </div>
    </div>
  );

  const renderRoles = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2">
        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-200 space-y-4">
            <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Ny kosmetisk rolle</h4>
            <div className="space-y-3">
                <input type="text" value={newRoleName} onChange={(e) => setNewRoleName(e.target.value)} placeholder="Navn (f.eks Nygutt)" className="w-full p-2.5 text-sm border border-slate-300 rounded-xl bg-white shadow-sm" />
                <div className="grid grid-cols-5 gap-2 p-2 bg-white rounded-xl border border-slate-200">
                    {COLORS.map(c => {
                        const style = ROLE_COLOR_MAP[c];
                        return (
                            <button key={c} onClick={() => setNewRoleColor(c)} className={`w-8 h-8 rounded-full border-2 transition-all ${style.solid} ${newRoleColor === c ? 'border-white scale-125 shadow-md ring-2 ring-slate-200' : 'border-transparent opacity-60'}`} />
                        );
                    })}
                </div>
                <Button fullWidth onClick={() => { if(newRoleName && onAddRole) { onAddRole(newRoleName, newRoleColor); setNewRoleName(''); } }}>Legg til rolle</Button>
            </div>
        </div>

        <div className="space-y-2 max-h-[40vh] overflow-y-auto pr-1 no-scrollbar">
            {roles.map(r => {
                const color = ROLE_COLOR_MAP[r.color] || ROLE_COLOR_MAP['slate'];
                return (
                    <div key={r.id} className="flex items-center justify-between p-3 bg-white border border-slate-100 rounded-xl">
                        <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase border ${color.bg} ${color.text} ${color.border}`}>{r.name}</div>
                        <button onClick={() => onRemoveRole && onRemoveRole(r.id)} className="p-2 text-slate-300 hover:text-red-500 rounded-lg transition-colors"><Trash2 size={16} /></button>
                    </div>
                );
            })}
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" onClick={onCancel}></div>
      <div className="relative bg-white rounded-[2.5rem] shadow-xl w-full max-w-sm max-h-[90vh] overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col">
        <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-white sticky top-0 z-20">
          <div>
            <h3 className="font-black text-slate-900 text-lg uppercase tracking-tight">Innstillinger</h3>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{currentUser?.name}</p>
          </div>
          <button onClick={onCancel} className="p-2 bg-slate-50 text-slate-400 hover:text-slate-600 rounded-2xl transition-colors"><X size={20} /></button>
        </div>

        {currentUser?.role === 'admin' && (
            <div className="px-4 py-2 bg-slate-50 border-b border-slate-100 flex gap-1 overflow-x-auto no-scrollbar">
                {(['profile', 'players', 'fines', 'roles'] as const).map(tab => (
                    <button 
                        key={tab} 
                        onClick={() => setActiveTab(tab)}
                        className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase whitespace-nowrap transition-all ${activeTab === tab ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-200'}`}
                    >
                        {tab === 'profile' ? 'Profil' : tab === 'players' ? 'Spillere' : tab === 'fines' ? 'Bøter' : 'Roller'}
                    </button>
                ))}
            </div>
        )}

        <div className="p-8 flex-1 overflow-y-auto no-scrollbar">
            {activeTab === 'profile' && renderProfile()}
            {activeTab === 'players' && renderPlayers()}
            {activeTab === 'fines' && renderFines()}
            {activeTab === 'roles' && renderRoles()}
        </div>
      </div>
    </div>
  );
};
